INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork', 0, 22.0, 7000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cork engraves cleanly at very low power and fast speed. At 33W, 22% prevents over-burning which destroys the cork surface texture. High speed ensures no dwell time heat build-up. The P2 produces excellent cork coaster batches on its large bed.; Machine: ACMER ACMER P2 33W (diode, 33W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm MDF', 6.0, 90.0, 200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Two passes for 6mm MDF. MDF fumes are toxic — ensure strong extraction. The built-in air assist is essential for MDF to reduce char and prevent smouldering. The P2 handles 6mm MDF better than 20W machines with noticeably less char on edges.; Machine: ACMER ACMER P2 33W (diode, 33W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 25.0, 3000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardboard cuts instantly at low power. Keep well below 40% to avoid ignition from the high wattage. The large bed is great for full-size packaging prototypes. Watch carefully — 33W can ignite cardboard faster than you''d expect if you''ve come from a lower-power machine.; Machine: ACMER ACMER P2 33W (diode, 33W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated Stainless Steel Tumbler', 0, 65.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Powder coat removal in one clean pass. Use a rotary attachment. The P2''s 33W makes tumbler engraving fast — suitable for production batches. Clean tumblers with IPA before engraving. Ensure the rotary is level and calibrated correctly in LightBurn.; Machine: ACMER ACMER P2 33W (diode, 33W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 70.0, 2800.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Strips anodising cleanly in one fast pass. No coating needed. The 33W module handles anodised aluminium quickly — batch dog tags or branded accessories efficiently. Use the P2''s array feature in LightBurn to fill the bed with items for each run.; Machine: ACMER ACMER P2 33W (diode, 33W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 52.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Bright white slate engrave at production speed. Invert your image. The P2''s large bed fits a 3×3 grid of standard 10cm coasters in one job. Wipe clean after engraving. Consistent results across the full sheet with the P2''s even power delivery.; Machine: ACMER ACMER P2 33W (diode, 33W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 30.0, 6000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Rich dark engrave on veg-tan leather at 30%. At 33W keep power low on leather — 30% is plenty. The built-in air assist helps clear debris from the engraved area. Fast throughput for leather goods production compared to 10-20W diodes.; Machine: ACMER ACMER P2 33W (diode, 33W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 75.0, 500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Baltic birch cuts consistently in one pass. The void-free core and 33W power combination gives near-zero waste cuts. Good for jig templates, interlocking parts, and production pieces where consistency matters more than speed.; Machine: ACMER ACMER P2 33W (diode, 33W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm Basswood Plywood', 6.0, 88.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '6mm basswood in one pass — a key advantage of the 33W module over standard 20W diodes. Focus at the top surface. Built-in air assist prevents the deep kerf from igniting. Clean cuts with minimal char compared to running multiple passes on lower-power machines.; Machine: ACMER ACMER P2 33W (diode, 33W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 28.0, 8000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Very fast raster engrave at 8000mm/min. 28% gives a warm medium-brown mark without burning. The P2''s large 400×400mm bed handles standard coaster and sign sizes well. Increase to 40% for darker marks on denser wood batches.; Machine: ACMER ACMER P2 33W (diode, 33W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 72.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'The P2''s 33W compressed beam cuts 3mm basswood in one clean pass at moderate power. Air assist is built in and essential. At 72% you preserve tube life while getting reliable single-pass cuts. The P2 competes directly with the Sculpfun S30 Pro at similar wattage and price.; Machine: ACMER ACMER P2 33W (diode, 33W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Black Acrylic', 3.0, 90.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Opaque black acrylic only — 450nm diode passes through clear acrylic. With 33W and air assist, cuts cleanly in a single pass at high speed. Remove protective paper before cutting. Constant power mode. Check for slight haze on edge — remove masking immediately if present.; Machine: ACMER ACMER P2 33W (diode, 33W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel', 0, 100.0, 200.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Tested directly on stainless steel at 200mm/min, 100% power, 1 pass with air assist on. Result: legible text/marks. Varying power and line interval (0.05–0.1mm) produces color oxidation effects (blues, oranges, purples) — a standout feature of the P2''s high power. Black acrylic paint pre-coating not required at full power.; Machine: ACMER ACMER P2 33W (diode, 33W); Air assist: on', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 90.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '33W cuts 3mm MDF cleanly in one pass with air assist. MDF produces heavy fumes — ventilate well. Air assist critical to prevent flare-up and keep lens clean. Multiple fast passes are an alternative for cleaner edges on thicker MDF (8mm: 2 passes).; Machine: ACMER ACMER P2 33W (diode, 33W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 22.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Kraft paper on A20 Pro.; Machine: Atomstack Atomstack A20 Pro (diode, 20W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock', 0, 35.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardstock on A20 Pro. Single clean pass.; Machine: Atomstack Atomstack A20 Pro (diode, 20W)', 'scraped_public', true, 'cut', 1.0);
