INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated Stainless Steel Tumbler', 0, 80.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher DPI tumbler pass for fine detail or photo on powder-coated stainless. Rotary required. Keep power moderate.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Plywood', 0, 65.0, 3000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Plywood engrave pass for surface marking and score lines. Adjust DPI to 300+ for photo engraving.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Plywood', 0, 100.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Generic plywood cut — 2 passes for cleaner edge. Pin material flat to avoid shift between passes. Actual passes depend on plywood thickness and glue density.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 80.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher DPI for fine text and logos on anodized aluminum. Slower speed with lower power gives crisper edges.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel', 0, 100.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Slower pass for deeper Cermark bond on stainless. Multiple thin coats of spray gives better adhesion.; Machine: Atomstack Atomstack A20 Pro (diode, 20W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Glass', 0, 55.0, 1000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Slower pass for finer detail on glass. Mask surface with wet tissue to improve result.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Marble Tile', 0, 85.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher speed with full power for faster throughput on marble tile engravings.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate (coaster)', 0, 90.0, 2200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher DPI for fine detail and photo work on slate coasters.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('2mm Basswood Plywood', 2.0, 100.0, 3000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2mm basswood cuts in a single pass on most diode lasers. Air assist keeps the cut clean and reduces char.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Spray Painted Metal', 0, 75.0, 2800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates spray paint to reveal bare metal. Thinner than powder coat so needs less power. Reduce power if paint splatters. Clean with IPA first.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Powder Coated Steel', 0, 80.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates powder coat to expose bare metal. Clean with IPA first. Black powder coat gives highest contrast. No Cermark needed.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated / Powder Coated Steel', 0, 80.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates powder coat to reveal bare metal beneath. Works on powder coated panels, signs, and flat stock. Clean with IPA first. Black powder coat gives highest contrast. No Cermark needed — laser burns off the coating directly.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
