INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock 300gsm', 0, 35.0, 6000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardstock 300gsm at 20W. Single pass, high speed.; Machine: Atomstack Atomstack A20 Pro (diode, 20W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 50.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Same laser module as X20 Pro. Atomstack officially lists cardboard as a supported cut material for the A20 Pro/X20 Pro/S20 Pro family. Community guidance from lahobbyguy.com/bb/viewtopic.php?t=33 and diode-laser-wiki.com is consistent across 20W diode laser brands. 800mm/min at 50% power is a reliable community starting point for standard corrugated cardboard.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 0, 100.0, 200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Identical laser module to X20 Pro. LA Hobby Guy forum (lahobbyguy.com/bb/viewtopic.php?t=4458 ''cut and print settings Atomstack A20 pro'') confirms A20 Pro users see similar MDF cutting behavior. One user reported 100mm/min at 100% power for 1 pass; 200mm/min / 2 passes with air assist is the more community-standard approach for cleaner results.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 55.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Same laser module as X20 Pro; same community settings apply. Atomstack officially lists slate as an engravable material for the A20 Pro. Source: lahobbyguy.com/bb/viewtopic.php?t=2916 and forum.lightburnsoftware.com/t/lightburn-grayscale-engraving-on-slate-using-lasermatic-mk2-20w-diode-laser/171784 (LaserMatic 20W diode, same power class).; Machine: Atomstack Atomstack A20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 30.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Same settings as X20 Pro — identical laser module. Source: lahobbyguy.com/bb/viewtopic.php?t=10243 and general 20W diode community guidance. Atomstack officially lists leather as an engravable material for the A20 Pro. Vegetable-tanned leather recommended; chrome-tanned leather releases toxic fumes.; Machine: Atomstack Atomstack A20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 0, 20.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Same official Atomstack engraving parameter table applies to A20 Pro as to X20 Pro. Line interval 0.1mm, 3000mm/min, 20% max power. Source: atomstackshop.com/blogs/engraving-and-cutting-parameter/lightburn-x20-pro-engraving-parameter-table and atomstack.com/pages/material-setting.; Machine: Atomstack Atomstack A20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 0, 90.0, 300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'A20 Pro, X20 Pro, and S20 Pro share identical 20W optical output and the same official parameter tables per Atomstack. Settings transfer directly. LA Hobby Guy forum (lahobbyguy.com/bb/viewtopic.php?t=4458 and t=3572) confirms A20 Pro users use similar 300mm/min / 90% settings for 3mm basswood. Air assist (F30/F60 kit) strongly recommended for clean cuts.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 100.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Birch glue layers vary in density — 3 passes needed for consistent cut-through. Check flatness of sheet.; Machine: Atomstack Atomstack A20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
