INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 95.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Atomstack Atomstack A5 Pro (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Balsa Wood', 0, 70.0, 300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2mm balsa cuts in 2 passes at 5W. Balsa is the most cuttable material for low-power diodes — the open cell structure absorbs the beam well. Use a pin bed to hold down the light balsa sheets during cutting. Great for model aircraft parts and scale prototypes.; Machine: Atomstack Atomstack A5 Pro (diode, 10W)', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 80.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Removes anodising cleanly to reveal bright aluminium underneath. Even 5W is sufficient for anodised aluminium — the anodised layer is very thin and absorbs the diode wavelength well. Excellent for dog tags, tumblers, and phone cases. No coating needed.; Machine: Atomstack Atomstack A5 Pro (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 35.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Kraft paper cuts cleanly at speed. The A5 Pro handles paper extremely well — low power and high speed prevent scorching. Great for stencils, labels, and paper decorations. Use a pin bed or honeycomb to support the paper.; Machine: Atomstack Atomstack A5 Pro (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 80.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Single-wall corrugated cardboard cuts well at 5W. Good for prototyping, gift boxes, and paper crafts. Keep power at 80% — going to 100% at slower speed risks ignition. Never leave the machine unattended when cutting cardboard.; Machine: Atomstack Atomstack A5 Pro (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 70.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Slate engraves white at these settings. Invert your image so engraved areas appear bright. Even a 5W diode produces excellent contrast on slate — this is one of the A5 Pro''s best use cases. Wipe clean with a damp cloth after to remove dust.; Machine: Atomstack Atomstack A5 Pro (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 50.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Leather engraves well at 50% — the 5W diode is more than enough for surface marking. Vegetable-tanned leather gives a rich dark brown. Keep power at 50% maximum; the thin diode beam concentrates a lot of energy and can cut through thin leather.; Machine: Atomstack Atomstack A5 Pro (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 100.0, 100.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '5 passes at full power barely cuts 3mm basswood — results are unreliable and edges are heavily charred. The A5 Pro is not a cutting machine at 5W. For anything thicker than 2mm balsa, use the A5 Pro for engraving only and cut on a more powerful machine.; Machine: Atomstack Atomstack A5 Pro (diode, 10W)', 'scraped_public', true, 'cut', 5.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 60.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'At 5W the A5 Pro engraves beautifully — its limitation is cutting, not engraving. 60% at 3000mm/min gives a warm brown mark on basswood. For photo engraving drop to 50% and use Stucki dithering in LightBurn. A great beginner engrave machine at this price point.; Machine: Atomstack Atomstack A5 Pro (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 100.0, 150.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '4 passes required without air assist. Slow but functional. Adding air assist upgrade makes a big difference.; Machine: Atomstack Atomstack A5 Pro (diode, 10W)', 'scraped_public', true, 'cut', 4.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 3.0, 80.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Easy clean cut on cardboard. Great for templating and prototyping.; Machine: Atomstack Atomstack A5 Pro (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
