INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('EVA Foam 3mm', 0, 70.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'EVA foam cuts on the S20 Pro at 70%. Turn off air assist. Heavy fumes — use maximum ventilation. Clean single-pass cuts for stamps and craft projects.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Craft Felt 3mm', 0, 80.0, 700.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Felt cuts in one pass on the S20 Pro at 80%. Turn off built-in air assist to prevent material blowing. Wool felt cuts cleaner than acrylic.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Chipboard 2mm', 0, 88.0, 1000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Chipboard cuts easily on the S20 Pro in one pass. 88% at 1000mm/min. The S20 Pro''s air assist helps clear the paper dust. Good for packaging prototypes and stencils.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cotton Fabric', 0, 75.0, 500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cotton can be cut on the S20 Pro at 75% power. Diode results are more singed than CO2. Pin material flat. Test on scrap first. The S20 Pro''s built-in air assist should be off when cutting fabric.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Bamboo', 0, 68.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Bamboo requires higher power on the S20 Pro. 68% at 2500mm/min gives good contrast on bamboo cutting boards and coasters. The S20 Pro has built-in air assist — keep it off for engraving to avoid blowing dust onto the engrave.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cedar', 0, 48.0, 3500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cedar is ideal for the S20 Pro — soft enough to engrave at modest power with great contrast. 48% at 3500mm/min. Run with good ventilation. Beautiful for aromatic home décor and gift boxes.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Alder', 0, 63.0, 2800.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Alder''s fine grain gives clean engraving on the S20 Pro at 63% power. Very similar to birch in behavior on 20W diode. Good for awards and sign blanks.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Pine', 0, 55.0, 3500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Pine engraves well on the S20 Pro — soft grain responds well to 20W. 55% at 3500mm/min gives rich contrast. Standard starting point for the S20 Pro community on pine signs and seasonal pieces.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cherry', 0, 60.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cherry engraves well on the S20 Pro. Finer grain than oak gives better results at 20W. 60% at 3000mm/min produces a warm brown mark with good detail. Good for gift personalization.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Oak', 0, 70.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Oak is challenging for 20W diode but the S20 Pro handles engraving at higher power settings. 70% at 2500mm/min gives a usable mark. Not as refined as CO2 but adequate for simple personalization on oak items.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Walnut Plywood', 3.0, 50.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'High contrast engrave on dark walnut. Reduce power vs basswood as walnut burns darker. Stunning results for gifts.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Walnut Plywood', 3.0, 100.0, 270.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Walnut is denser than basswood — 2 passes needed. Beautiful dark grain for premium personalised products.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Bamboo Cutting Board', 0, 62.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Great contrast on bamboo. Popular for personalised kitchen gifts. Wipe residue with damp cloth after engraving.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 3.0, 80.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Fast clean cut on cardboard. Skip air assist — can cause flare-ups. Good for packaging prototypes and templates.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork 3mm', 3.0, 30.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Easy cork engrave. Keep power low to avoid burning too deep into the porous material.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 100.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Birch glue layers are inconsistent — 3 passes for reliable cut-through at 20W. Check flatness before long runs.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 65.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Clean mark on black anodized dog tags, keychains, and small signs. Increase to 75% for lighter anodize colours.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 72.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Bright white engrave on black slate. Invert image. Consistent results with the S20 Pro. Wipe with a damp cloth after.; Machine: Atomstack Atomstack S20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 100.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2–3mm veg-tan in 2 passes. Air assist on for edge quality. Test on scrap — leather thickness varies significantly.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 42.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Clean dark mark on veg-tan. 42% is a solid starting point — adjust up or down for your hide thickness. Built-in air assist helps clear smoke for cleaner detail.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 100.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'MDF requires 3 passes at 20W. Air assist helps manage the heavy char. Multiple passes at moderate speed give cleaner edges than one slow pass.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 55.0, 3500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Good fill engrave at 3500 mm/min. The built-in air assist on the S20 Pro keeps the lens clear during long engraves. Bump to 60% for a darker mark.; Machine: Atomstack Atomstack S20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
