INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Leather', 0, 55.0, 5000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Atomstack Atomstack X20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 50.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'General 20W diode laser community guidance from LA Hobby Guy (lahobbyguy.com/bb/viewtopic.php?t=33 ''Laser Power & Speed Settings for 20W Diode laser'') and Diode Laser Wiki (diode-laser-wiki.com/documentation/guideline-settings/). Cardboard is an easy material for 20W diodes; 800mm/min at 50% is a standard community starting point for corrugated/craft cardboard. Speeds of 500-1000mm/min at 40-60% are the typical community-tested range. Air assist helps prevent flare-ups. Adjust down for thicker cardboard.; Machine: Atomstack Atomstack X20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 55.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Community-tested on 20W diode lasers via LA Hobby Guy (lahobbyguy.com/bb/viewtopic.php?t=2916 ''Settings for Slate''). Multiple users with 20W machines (including Atomstack X20 Pro) report 4000mm/min at 55% power as a reliable starting point. Lower power + faster speed consistently yields cleaner, lighter contrast. Wiping slate with acetone before engraving improves results. No clear coat needed post-engrave.; Machine: Atomstack Atomstack X20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 55.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Community-sourced from LA Hobby Guy / LightBurn forum discussions. Atomstack X20 Pro user reported 4000mm/min at 55% power giving good results on anodized aluminum — low power + fast speed gives cleaner marks vs. high power + slow speed which digs in and looks rough. Source: diode laser community consensus at lahobbyguy.com/bb/viewtopic.php?t=33 and forum.lightburnsoftware.com/t/diode-laser-speed-and-power-guide/43192. Diode lasers ablate the anodized coating only; they do not mark bare aluminum.; Machine: Atomstack Atomstack X20 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 3.0, 80.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Fast clean cut on packaging cardboard.; Machine: Atomstack Atomstack X20 Pro (diode, 20W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 55.0, 5000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, '20W Atomstack can engrave significantly faster than 10W. Good clean result at this speed. Faster cycle time for production.; Machine: Atomstack Atomstack X20 Pro (diode, 20W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
