INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Walnut', 0, 12.0, 27000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Boss Boss LS-1630 (co2, 100W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('EVA Foam 3mm', 0, 15.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'EVA foam cuts very cleanly at minimal power on the 100W CO2. 15% at 1500mm/min — lowest power that achieves a clean cut. CO2 cuts foam far more cleanly than diode. Heavy fumes — run full ventilation. Excellent for cosplay, protective inserts, and custom packaging.; Machine: Boss Boss LS-1630 (co2, 100W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Craft Felt 3mm', 0, 22.0, 1000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Felt cuts cleanly on the Boss. 22% at 1000mm/min. CO2 gives cleaner edges on felt than diode. Wool felt preferred. No air assist. Large format enables high-volume ornament and craft production runs.; Machine: Boss Boss LS-1630 (co2, 100W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Chipboard 2mm', 0, 20.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Chipboard cuts effortlessly on the 100W Boss at very low power and very high speed. 20% at 2000mm/min. Excellent for high-volume packaging prototype work and stencil cutting. The large bed enables full-sheet runs.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cotton Fabric', 0, 18.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cotton cuts cleanly on the Boss LS-1630 at very low power / high speed. 18% at 1200mm/min. CO2 cuts fabric far better than diode — minimal singeing. Pin to a honeycomb bed. The large bed size makes the Boss ideal for fabric cutting production work.; Machine: Boss Boss LS-1630 (co2, 100W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Bamboo', 0, 35.0, 500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Bamboo engraves well on the Boss LS-1630. 35% at 500mm/min handles the harder silica-rich grain. Production-ready throughput for bamboo cutting boards, coasters, and utensils. The large 16"×30" bed fits multiple items per run.; Machine: Boss Boss LS-1630 (co2, 100W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cedar', 0, 75.0, 900.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cedar cuts very fast in one pass on the 100W Boss. 900mm/min at 75%. Excellent throughput for cedar jewelry boxes, drawer liners, and aromatic products. Air assist on. Aromatic smoke at high volume — strong ventilation essential.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cedar', 0, 25.0, 600.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cedar engraves at very low power on the 100W Boss — softwood combined with high wattage means minimal percentage needed. 25% at 600mm/min. Heavy aromatic smoke — run full ventilation. Beautiful contrast and rich reddish tones.; Machine: Boss Boss LS-1630 (co2, 100W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Alder', 0, 30.0, 550.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Alder engraves cleanly on the Boss LS-1630. 30% at 550mm/min. Fine grain gives crisp detail. Great for production signage and award plaques where fine text precision matters.; Machine: Boss Boss LS-1630 (co2, 100W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Pine', 0, 80.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Pine cuts effortlessly in one fast pass on the 100W Boss. 800mm/min at 80%. Soft grain and high power = excellent throughput. Air assist manages resin smoke. The 16"×30" bed fits full pine planks for sign production.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Pine', 0, 28.0, 600.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Pine engraves fast on the 100W Boss. Low percentage power to avoid burning the resin-rich softwood. 28% at 600mm/min gives warm medium-brown marks. Very fast throughput — ideal for high-volume pine plank signs and seasonal items.; Machine: Boss Boss LS-1630 (co2, 100W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cherry', 0, 85.0, 700.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cherry cuts in one fast pass on the 100W Boss. 700mm/min at 85%. Clean edges, minimal charring — cherry is one of the cleanest-cutting hardwoods. Air assist on for best edge quality. High throughput for production cutting.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cherry', 0, 30.0, 550.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cherry engraves beautifully on the Boss LS-1630 — 100W with low percentage gives excellent control. 30% at 550mm/min. Fine grain produces professional-quality engrave suitable for production work. One of the best machine+material pairings for high-volume personalization.; Machine: Boss Boss LS-1630 (co2, 100W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Oak', 0, 90.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '100W CO2 cuts oak in one clean pass — a major advantage over lower-wattage machines. 600mm/min at 90%. Clean edges, minimal char. Air assist on. The LS-1630''s large bed (16"×30") is well-suited for oak plank work and large sign blanks.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Oak', 0, 35.0, 500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'The Boss LS-1630''s 100W tube handles oak effortlessly. Lower percentage power needed at this wattage. 35% at 500mm/min gives rich dark marks. Dial back to 25% for a lighter, more subtle engrave. Excellent for high-volume production engraving of oak plaques and signage.; Machine: Boss Boss LS-1630 (co2, 100W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Corrugated Cardboard 4mm', 0, 35.0, 4200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Equivalent to ~70mm/s. Extrapolated from Noisebridge 100W chart (cardboard: 40% power / speed 1 in Epilog native units ≈ fast speed) and Boss Laser community. 100W easily cuts cardboard — keep power low to prevent scorching. Never leave unattended due to fire risk. Heavier chipboard needs 50–55% power.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather (Veg-Tan, ~3mm)', 0, 22.0, 12000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Equivalent to ~200mm/s. Derived from LightBurn forum leather threads and Monport 100W leather engrave guide (monportlaser.com). Higher wattage machine allows faster speed at similar power vs 80W. DPI: 300 LPI. Low power critical — leather burns easily. Test at 15% power first and increase until desired depth achieved.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather (Veg-Tan, ~3mm)', 0, 55.0, 900.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Equivalent to ~15mm/s. Boss official settings list leather 1.6mm at 100W: 70% power / speed 40. For 3mm veg-tan, reduce speed to ~15mm/s at 55% power. Monport 100W leather guide confirms 40–60W effective power range for leather. Light-to-moderate air assist. Chrome-tanned leather is a fume hazard — verify leather type.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm Baltic Birch Plywood', 0, 75.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Equivalent to ~20mm/s. Boss official chart (bosslaser.com/laser-settings/) lists Sande plywood 1/4" at 100W: 70% power / speed 20 (native). Baltic birch at similar thickness aligns. Cross-referenced with Noisebridge 100W settings wiki and settingsmag.com. Voids or knots in lesser-grade ply may need 2 passes. High air assist. Power cap at 75% to preserve tube life.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 80.0, 21000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Equivalent to ~350mm/s. CO2 removes anodized layer only — not bare metal. From LightBurn forum (forum.lightburnsoftware.com/t/is-it-possible-to-engrave-aluminum-parameters/28508): recommendation is max speed at 70–85% power for CO2 ≥80W. DPI: 300–500 LPI. Black/dark anodizing produces highest contrast. Test with a grid at varying speeds/powers first.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 0, 65.0, 1800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Equivalent to ~30mm/s. Boss official settings table (bosslaser.com/laser-settings/) for 100W MDF 1/4" lists power 80 at speed 5 (native units). 3mm is thinner so speed can increase and power decrease proportionally. Cross-referenced with CAMFive 100W reference chart and Noisebridge 100W wiki (noisebridge.net/wiki/Old_100W_Laser_Cutter_Settings_for_Known_Good_Materials). High air assist required.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic (Cast)', 0, 60.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Equivalent to ~25mm/s. Boss Laser official settings reference (bosslaser.com/laser-settings/) lists 100W acrylic at ~40% power/15 speed in native units; cross-referenced with Pumping Station One Boss Laser wiki (wiki.pumpingstationone.org/wiki/Boss_Laser_Settings) and settingsmag.com chart. Low air pressure (8–12 PSI) for clear flame-polished edges on cast acrylic. Boss native speed units are relative (0–100 scale) — LightBurn mm/s equivalent is ~25mm/s.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('12mm MDF', 12.0, 70.0, 840.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '100W cuts 12mm MDF in one pass. Excellent ventilation mandatory at this thickness — MDF fumes are substantial. Air assist on.; Machine: Boss Boss LS-1630 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Rubber Stamp Material', 0, 30.0, 18000.0, NULL, NULL, NULL, NULL, NULL, 0.051, NULL, NULL, 'Deep clean relief for stamp blanks. 500 DPI for fine text. Invert design.; Machine: Boss Boss LS-1630 (co2, 100W); DPI: 500', 'scraped_public', true, 'engrave', 1.0);
