INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Black Anodized Aluminum', 0, 18.0, 168000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Very fast cycle. Bright white on black anodized.; Machine: ComMarker Commarker B6 30W (fiber, 30W); DPI: 500', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 20.0, 150000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Extra power allows faster speed. Crisp white result.; Machine: ComMarker Commarker B6 30W (fiber, 30W); DPI: 500', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated / Powder Coated Steel', 0, 60.0, 36000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Extra 10W over B4 means coating ablation is cleaner and faster. Slight speed increase vs 20W. Slight defocus +2mm on curved items. ComMarker B6 60W blog material settings + LightBurn painted tumbler thread (scaled for 30W). | Freq: 40kHz, pulse: 100ns, line interval: 0.05mm; Machine: ComMarker Commarker B6 30W (fiber, 30W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Black Anodized Aluminum', 0, 100.0, 120000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Creates bright white/silver mark on black anodize. Short ns pulse critical. Same approach as general anodized Al but maximise power to ensure full coat ablation in one pass. LightBurn material library listings for B6 30W confirm this range. | Freq: 55kHz, pulse: 4ns, line interval: 0.04mm; Machine: ComMarker Commarker B6 30W (fiber, 30W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 80.0, 120000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'White mark result on colored anodize. Short pulse (4 ns) + high frequency prevents burning. 30W reference from barchlaser.com MOPA aluminum + white aluminum setting (100% / 2000mm/s / 55kHz) adapted for mark-not-cut. | Freq: 55kHz, pulse: 4ns, line interval: 0.05mm; Machine: ComMarker Commarker B6 30W (fiber, 30W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel', 0, 90.0, 6000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Deep material removal / mechanical engraving. Low frequency is more aggressive. Multiple passes with slight defocus between passes can clear debris. LightBurn forum 30W settings thread. | Freq: 25kHz, pulse: 200ns, line interval: 0.03mm; Machine: ComMarker Commarker B6 30W (fiber, 30W)', 'scraped_public', true, 'engrave', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Carbon Steel', 0, 85.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Deep dark mark on carbon steel — great for tool marking, knife blades, and industrial parts. The result is rust-resistant when the oxide layer forms properly. Wipe with a dry cloth after marking to remove debris.; Machine: ComMarker Commarker B6 30W (fiber, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Titanium', 0, 65.0, 1200.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Colour marking on titanium — the colour changes with speed. At 1200mm/min you get warm gold tones. Slow down to 800mm/min for deeper blue/purple. Speed affects colour more than power on titanium. Always test on a scrap piece first.; Machine: ComMarker Commarker B6 30W (fiber, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Brass', 0, 75.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Dark oxide mark on raw brass. Works well for trophies, plaques, and jewellery findings. Polished brass needs slightly higher power than brushed. Rinse after engraving to remove any residue.; Machine: ComMarker Commarker B6 30W (fiber, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
