INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Walnut', 0, 100.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '5W diode surface mark only; hardwood may char at edges; Machine: Creality Creality Falcon (diode, 10W); Air assist: on', 'scraped_public', true, 'engrave', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock', 0, 20.0, 6000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Creality 22W official wiki parameters list 15% power at 6000 mm/min for 0.2mm red card paper engrave. Community on Creality forum and LightBurn forum confirms similar settings translate to 5W with slight power increase. crealityfalcon.com material settings series blog confirms cardstock engraving at high speed / low power is universal across Falcon line.; Machine: Creality Creality Falcon (diode, 10W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 70.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Tom''s Hardware review of CR Laser Falcon (5W) notes corrugated cardboard produces excessive smoke and fire risk; single-layer chipboard/cardboard recommended. LA Hobby Guy (t=7599) reports cardboard outline cut at ~2000 mm/min at moderate power for light card; forum.creality.com new-user thread confirms 5W cuts thin cardboard in 1–2 passes at 70–80% power. Air assist strongly recommended to control flare-ups.; Machine: Creality Creality Falcon (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 0, 40.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Scaled from Creality 10W official table (Scribd doc 651622034): 10W uses 40% power at 3000 mm/min for basswood engrave, 1 pass. The 5W shares the same GRBL platform; community on Creality forum and LightBurn forum (forum.lightburnsoftware.com) report similar engrave speeds but bump power to ~40-60% to compensate for lower wattage. Official ''Recommended Parameters for 5W'' (Scribd 830587043) confirms basswood engraving in same speed range.; Machine: Creality Creality Falcon (diode, 10W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 92.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Two passes through 3mm Baltic birch. More consistent than standard plywood due to the void-free core. The Falcon gives clean results on Baltic birch with air assist. Good for jig templates and small production parts where two-pass cuts are acceptable.; Machine: Creality Creality Falcon (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('2mm MDF', 2.0, 88.0, 200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Two passes for 2mm MDF. MDF fumes are toxic — ensure good room ventilation. Air assist significantly reduces char on MDF. The Falcon handles 2mm MDF well for small signs and craft pieces. 3mm MDF at 10W is frustrating — needs 4+ passes with heavy char.; Machine: Creality Creality Falcon (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated Stainless Steel Tumbler', 0, 72.0, 2200.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Removes powder coat to reveal bare metal. Use a rotary attachment and calibrate steps-per-mm in LightBurn. Clean the tumbler surface with IPA first. The Falcon''s 10W is sufficient for powder coat removal in one pass on most brands of coated tumblers.; Machine: Creality Creality Falcon (diode, 10W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork', 0, 30.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Clean cork engrave at low power. At 10W, 30% prevents over-burning which ruins the cork texture. Fast speed ensures the laser doesn''t dwell too long on any spot. The Falcon produces excellent cork coasters — a popular product for entry-level laser makers.; Machine: Creality Creality Falcon (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 25.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Low power and high speed cuts kraft paper cleanly without edge browning. Great for gift tags and paper decorations. The Falcon handles paper well — consistent cuts at these settings.; Machine: Creality Creality Falcon (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork 3mm', 3.0, 95.0, 350.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cork cuts in 2 passes at 5W. No air assist recommended — can cause cork blowout. Clean edge.; Machine: Creality Creality Falcon (diode, 10W)', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork 3mm', 3.0, 50.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cork is one of the best materials for a 5W laser. Great contrast, good depth. Ideal starter project for beginners on this machine.; Machine: Creality Creality Falcon (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 3.0, 90.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardboard is easy for a 5W. Clean cut, slight char on edges. Good for paper crafts and templates.; Machine: Creality Creality Falcon (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated Stainless Steel Tumbler', 0, 80.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher DPI tumbler pass for fine detail or photo on powder-coated stainless. Rotary required. Keep power moderate.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Plywood', 0, 65.0, 3000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Plywood engrave pass for surface marking and score lines. Adjust DPI to 300+ for photo engraving.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Plywood', 0, 100.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Generic plywood cut — 2 passes for cleaner edge. Pin material flat to avoid shift between passes. Actual passes depend on plywood thickness and glue density.; Machine: Creality Creality Falcon2 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 80.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher DPI for fine text and logos on anodized aluminum. Slower speed with lower power gives crisper edges.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel', 0, 100.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Slower pass for deeper Cermark bond on stainless. Multiple thin coats of spray gives better adhesion.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Glass', 0, 55.0, 1000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Slower pass for finer detail on glass. Mask surface with wet tissue to improve result.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Marble Tile', 0, 85.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher speed with full power for faster throughput on marble tile engravings.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate (coaster)', 0, 90.0, 2200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher DPI for fine detail and photo work on slate coasters.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Spray Painted Metal', 0, 75.0, 2800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates spray paint to reveal bare metal. Thinner than powder coat so needs less power. Reduce power if paint splatters. Clean with IPA first.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Powder Coated Steel', 0, 80.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates powder coat to expose bare metal. Clean with IPA first. Black powder coat gives highest contrast. No Cermark needed.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated / Powder Coated Steel', 0, 80.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates powder coat to reveal bare metal beneath. Works on powder coated panels, signs, and flat stock. Clean with IPA first. Black powder coat gives highest contrast. No Cermark needed — laser burns off the coating directly.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Mirrored Acrylic', 0, NULL, 4500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engrave from the BACK side for a clean mirrored result.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 254', 'scraped_public', true, NULL, 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic (Cast)', 0, NULL, 4800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Creality Creality Falcon2 (diode, 22W); DPI: 254', 'scraped_public', true, NULL, 1.0);
