INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 40.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Great results on leather. 22W handles leather well.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 0, 100.0, 300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 passes for MDF at 22W. Slow but works. Air assist on.; Machine: Creality Creality Falcon2 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 0, 55.0, 4000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Good fill engrave speed for the Falcon2. Bump to 60% power for darker result.; Machine: Creality Creality Falcon2 (diode, 22W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 0, 100.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 passes needed at 22W for consistent cut through. Clean result.; Machine: Creality Creality Falcon2 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Leather', 0, 100.0, 1800.0, NULL, NULL, 0.0, NULL, NULL, NULL, NULL, NULL, 'Cut vegetable-tanned leather at full power 2 passes. Faux/chrome-tanned leather produces toxic fumes — avoid.; Machine: Creality Creality Falcon2 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
