INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock 300gsm', 0, 25.0, 9000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardstock 300gsm at 40W. Minimal power needed.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('EVA Foam 3mm', 0, 62.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'EVA foam cuts cleanly on the Falcon2. 62% at 800mm/min avoids excessive melting. No air assist. Heavy fumes — ventilate well. Clean edges for craft and cosplay use.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Craft Felt 3mm', 0, 75.0, 900.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Felt cuts cleanly on the Falcon2 in one pass. No air assist. Wool felt gives cleaner edges than synthetic. Good for ornaments and craft projects.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cotton Fabric', 0, 72.0, 550.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cotton cuts on the Falcon2 at 72% power. Results are acceptable but more singed than CO2. No air assist — hold material flat with pins. Test on scrap fabric first.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Bamboo', 0, 70.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Bamboo requires higher power on the Falcon2 due to its hardness. 70% at 2500mm/min gives acceptable contrast. Consistent results on flat bamboo stock. Popular in the Creality community for cutting board personalization.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cedar', 0, 45.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cedar is ideal for the Falcon2 — softness compensates for the 22W limitation. 45% at 4000mm/min gives beautiful results. Aromatic smoke is heavy. Beautiful engraving for home décor items.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Alder', 0, 65.0, 2800.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Alder engraves cleanly on the Falcon2. 65% at 2800mm/min gives good contrast with fine grain detail. Very similar in behavior to birch on this machine. Good for signage and awards.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Pine', 0, 100.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Pine can be cut on the Falcon2 at 22W but requires 3 passes at full power. Air assist critical for resin smoke management. Results are functional but edges have noticeable charring. Recommend higher wattage for regular pine cutting.; Machine: Creality Creality Falcon2 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Pine', 0, 55.0, 3500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Pine engraves well on the Falcon2 — softwood responds better than hardwood to 22W diode. 55% at 3500mm/min. Good contrast. Standard starting point for pine signs and seasonal décor on this machine.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cherry', 0, 62.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cherry engraves reasonably well on the Falcon2. Finer grain than oak gives better results at 22W. 62% at 3000mm/min gives a warm medium-brown mark. Good for personalized gift items.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Oak', 0, 68.0, 2800.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Oak engraving is possible on the Falcon2 22W but requires higher power for the dense hardwood. 68% at 2800mm/min gives a usable mark. Results are less refined than CO2 or higher-wattage diode. Fine detail is preserved reasonably well.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock', 0, 15.0, 6000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Creality Falcon2 22W official wiki and Scribd 661034488: 15% power, 6000 mm/min, 1 pass for 0.2mm red card paper engrave. store.creality.com parameter guide confirms this entry. Recommended to test darker card colors at slightly lower power as dark pigment absorbs more energy.; Machine: Creality Creality Falcon2 (diode, 22W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock', 0, 50.0, 4000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Creality Falcon2 22W official wiki and Scribd 661034488: 50% power, 4000 mm/min, 1 pass for 0.2mm red card paper cut. store.creality.com blog ''Falcon2 Laser Engraving & Cutting Parameter Settings Guide'' lists this exact entry. LA Hobby Guy and golasergo.com review both note the 22W cuts cardstock cleanly and quickly at these settings.; Machine: Creality Creality Falcon2 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 60.0, 5000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Creality Falcon2 22W Recommended Parameters wiki (wiki.creality.com/en/laser-engraver/falcon2/22W-recommended-parameters) and Scribd doc 661034488 list kraft paper / corrugated cardboard cutting parameters in the 3000–6000 mm/min range at 40–70% power. Tom''s Hardware and community reviewers note 22W easily cuts corrugated cardboard in 1 pass at moderate power/high speed. Air assist recommended to prevent flare-up.; Machine: Creality Creality Falcon2 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Mirrored Acrylic', 0, NULL, 440.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engrave from the BACK side for a clean mirrored result.; Machine: Epilog Epilog Fusion Pro (co2, 50W); DPI: 300', 'scraped_public', true, NULL, 1.0);
