INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 70.0, 900.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Epilog Epilog Zing 24 (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 30.0, 12000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Epilog Zing Material Settings PDF (official): anodized aluminum engraves at high speed, low power. 100% speed / 30% power / 500 DPI is a recommended starting point from Epilog documentation — anodized aluminum needs far less power than wood. Text is sharpest at 500 DPI; 400 DPI also acceptable. Speed expressed as Epilog percentage (1–100). Source: epiloglaser.com/assets/downloads/zing-material-settings.pdf + epiloglaser.com/support/material-settings; Machine: Epilog Epilog Zing 24 (co2, 30W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Rubber', 0, 65.0, 10800.0, NULL, NULL, NULL, NULL, NULL, 0.051, NULL, NULL, 'Custom rubber stamp engraving at 500 DPI — the Epilog is widely used by stamp makers. The fine beam and precise motion produce sharp, deep reliefs. Use stamp rubber or laser-safe rubber (not natural rubber which produces toxic fumes). Wash the stamp with soap and water after engraving to remove residue.; Machine: Epilog Epilog Zing 24 (co2, 30W); DPI: 500', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 60.0, 1920.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Baltic birch cuts beautifully on the Epilog. The consistent power delivery means no variation across a full sheet — all pieces are identical, which matters for production runs. The Epilog''s print driver makes it easy to run repeated jobs from any design software.; Machine: Epilog Epilog Zing 24 (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Walnut Plywood', 3.0, 65.0, 1680.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Walnut plywood cuts cleanly and precisely. The Epilog''s accuracy makes it ideal for intricate wooden jewellery and decorative panels. Cut edges have minimal char compared to budget CO2 machines — this is partly the tube quality and partly the precision motion system.; Machine: Epilog Epilog Zing 24 (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm MDF', 6.0, 85.0, 900.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '6mm MDF cuts in one pass with good edge quality. MDF fumes are toxic — Epilog machines are often used with professional inline air filtration units (e.g. UAS or Purex). Don''t rely on an open window for extraction with MDF; use dedicated filtration especially in school or office environments.; Machine: Epilog Epilog Zing 24 (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 25.0, 12000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardboard cuts cleanly at high speed and low power. The Epilog''s autofocus system ensures consistent focus height even on slightly warped card stock. Used widely in schools and fab labs for rapid packaging prototypes and architectural models.; Machine: Epilog Epilog Zing 24 (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 70.0, 18000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Bright, consistent white engrave on slate with no banding — one area where the Epilog clearly outperforms budget CO2 machines. The servo-driven head maintains even speed across the slate surface. Wipe clean after engraving. Great for wedding gifts and memorial items.; Machine: Epilog Epilog Zing 24 (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 70.0, 1800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Clean cuts through 2mm veg-tan leather. Epilog''s consistent power output means no undercut or overcut variation across the piece. Thicker leather (3-4mm) needs 2 passes at 70%. The Zing 24''s small 610×305mm bed is sufficient for most jewellery and accessory production.; Machine: Epilog Epilog Zing 24 (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 20.0, 21000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'The Epilog gives exceptionally sharp leather engraving — fine text down to 6pt is legible. At 20% and 350mm/s you get a deep, dark mark without cutting through on standard 2mm veg-tan. For lighter colour marking (hot-stamping look) drop to 12%.; Machine: Epilog Epilog Zing 24 (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic', 3.0, 18.0, 24000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Crisp frosted engrave at 18%. The Epilog''s consistent power delivery means no streaking or banding across wide raster fills — a common problem on cheaper CO2 machines. For 3D relief engraving use ''vary power'' mode with a greyscale depth map.; Machine: Epilog Epilog Zing 24 (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic', 3.0, 80.0, 1080.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Flame-polished edges on cast acrylic. The Epilog''s precise motion control means cuts are straight and smooth — no wobble from belt slack. Always use cast acrylic (not extruded) for cutting. Extruded acrylic can produce chlorine gas and doesn''t polish as cleanly.; Machine: Epilog Epilog Zing 24 (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 30.0, 18000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Fast, consistent engrave at 300mm/s and 30%. The Zing 24''s precision servo motors produce extremely sharp lines even at high speed. For photo engraving use 400 DPI — the Epilog handles fine detail far better than gantry machines with belt drives. ''Stucki'' or ''Jarvis'' dithering works best.; Machine: Epilog Epilog Zing 24 (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 55.0, 2100.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Epilog machines are extremely consistent — these settings produce clean cuts with minimal char on every sheet. The Zing 24''s sealed CO2 tube maintains calibration over years of use, unlike Chinese tube machines that drift. Always use the Epilog print driver or LightBurn''s Epilog profile for correct speed/power mapping.; Machine: Epilog Epilog Zing 24 (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Rubber Stamp Material', 0, 65.0, 28800.0, NULL, NULL, NULL, NULL, NULL, 0.051, NULL, NULL, 'Deep clean relief for stamps. 500 DPI for fine detail. Invert design.; Machine: Epilog Epilog Zing 24 (co2, 30W); DPI: 500', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Mirrored Acrylic', 0, NULL, 440.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engrave from the BACK side for a clean mirrored result.; Machine: Flux FLUX Ador (co2, 50W); DPI: 300', 'scraped_public', true, NULL, 1.0);
