INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 70.0, 900.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Flux Flux Beamo (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork', 0, 15.0, 15000.0, NULL, NULL, NULL, NULL, NULL, 0.102, NULL, NULL, 'Clean cork engrave at very low power. The Beamo makes excellent cork coasters and trivets — the small bed is the perfect size for a set of 4. Lower power than you''d expect is needed at 30W. Beam Studio''s repeat array feature makes batching 4 coasters in one job easy.; Machine: Flux Flux Beamo (co2, 30W); DPI: 250', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('2mm MDF', 2.0, 60.0, 1080.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2mm MDF cuts in one pass. The Beamo''s enclosed design contains MDF fumes reasonably well but still ensure you''re exhausting outside. 3mm MDF needs 2 passes at these settings. The Beamo is popular with miniature makers and table-top gaming terrain builders who work at small scale.; Machine: Flux Flux Beamo (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Walnut Plywood', 3.0, 65.0, 900.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Walnut plywood cuts beautifully on the Beamo. The small work area suits premium small-format items like coasters, keyrings, and ornaments where walnut''s natural beauty justifies the material cost. Beam Studio''s camera overlay makes positioning on the wood grain very satisfying.; Machine: Flux Flux Beamo (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 12.0, 12000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Very low power cuts kraft paper cleanly. The Beamo''s camera makes placing paper designs easy and accurate. Great for wedding stationery, gift tags, and paper decorations. The precise lid camera alignment is one of the Beamo''s standout features for small-format work.; Machine: Flux Flux Beamo (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 25.0, 6000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardboard cuts quickly at low power. The Beamo''s enclosed design is safer for cardboard cutting than open-frame machines. Good for packaging prototypes and gift box designs sized for the A5 work area. Beam Studio''s shape library has box templates built in.; Machine: Flux Flux Beamo (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 65.0, 12000.0, NULL, NULL, NULL, NULL, NULL, 0.102, NULL, NULL, 'Bright white engrave on slate. Invert your image in Beam Studio. The Beamo produces excellent slate results — CO2 wavelength works well on stone. The small bed fits standard 10×10cm coasters perfectly. Wipe clean after engraving to reveal full contrast.; Machine: Flux Flux Beamo (co2, 30W); DPI: 250', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 65.0, 1320.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cuts through 2mm veg-tan leather cleanly. The Beamo''s small bed limits you to smaller leather pieces — earrings, keychains, and patches rather than full bags. The enclosed design makes leather cutting more pleasant than open-frame machines.; Machine: Flux Flux Beamo (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 18.0, 15000.0, NULL, NULL, NULL, NULL, NULL, 0.102, NULL, NULL, 'Rich dark engrave at 18%. The Beamo handles leather very well — CO2 wavelength absorbs perfectly into leather. Beam Studio''s curve-based power adjustment lets you fine-tune results without running a full test matrix. One of the best compact machines for leather goods.; Machine: Flux Flux Beamo (co2, 30W); DPI: 250', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic', 3.0, 15.0, 15000.0, NULL, NULL, NULL, NULL, NULL, 0.102, NULL, NULL, 'Clean frosted engrave at 15%. The Beamo''s CO2 beam gives excellent results on acrylic — far better than any diode laser at the same price. Use the ''invert'' option in Beam Studio for light-on-dark effects. Great for awards and personalised gifts.; Machine: Flux Flux Beamo (co2, 30W); DPI: 250', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic', 3.0, 70.0, 720.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Flame-polished edges on 3mm cast acrylic. The Beamo''s enclosed design contains acrylic fumes well — but still connect the exhaust to a window or duct. Beam Studio has built-in acrylic parameters that are well-tuned for the 30W tube.; Machine: Flux Flux Beamo (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 20.0, 12000.0, NULL, NULL, NULL, NULL, NULL, 0.102, NULL, NULL, 'Fast raster engrave at 200mm/s. Beam Studio''s engrave presets work well for standard materials. The Beamo''s camera-based alignment makes it easy to position artwork precisely on each workpiece — particularly useful for personalised items where placement matters.; Machine: Flux Flux Beamo (co2, 30W); DPI: 250', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 55.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'The Beamo''s 30W CO2 tube cuts 3mm basswood cleanly. Beam Studio''s Proofgrade-style presets (called ''parameters'') give a good starting point. The small 300×210mm bed limits batch sizes but is perfect for A5-scale projects like coasters, tags, and keyrings.; Machine: Flux Flux Beamo (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Black Acrylic', 3.0, 18.0, 12000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'White frosted engrave on black acrylic. Very high contrast. Low power — CO2 at 30W still needs gentle touch for surface engrave.; Machine: Flux Flux Beamo (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Bamboo Cutting Board', 0, 32.0, 12000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Excellent contrast on bamboo. Beamo''s compact 300×210 bed suits smaller cutting boards. Popular for personalised kitchen gifts.; Machine: Flux Flux Beamo (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 65.0, 420.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Single pass through 3mm MDF. MDF fumes are heavy — run Beamo with built-in HEPA filter or strong external vent.; Machine: Flux Flux Beamo (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Mirrored Acrylic', 0, NULL, 1700.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engrave from the BACK side for a clean mirrored result.; Machine: Glowforge Glowforge Aura (diode, 6W); DPI: 254', 'scraped_public', true, NULL, 1.0);
