INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('5mm Plywood', 0, 18.0, 9600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '5mm plywood engraves well. Deeper relief: reduce speed or increase power slightly.; Machine: Glowforge Glowforge Pro (co2, 45W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('5mm Plywood', 5.0, 55.0, 720.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '5mm plywood requires multiple passes on diode — pin material flat between passes. Air assist essential.; Machine: Glowforge Glowforge Pro (co2, 45W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('2mm Basswood Plywood', 0, 11.0, 22800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2mm basswood engraves with deep contrast. 300 DPI is the sweet spot — higher increases burn time significantly.; Machine: Glowforge Glowforge Pro (co2, 45W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('2mm Basswood Plywood', 2.0, 35.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2mm basswood cuts in a single pass on most diode lasers. Air assist keeps the cut clean and reduces char.; Machine: Glowforge Glowforge Pro (co2, 45W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm Clear Acrylic', 0, 22.0, 7200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'CO2 wavelength is absorbed by clear acrylic — diode lasers pass straight through. Keep power low for engrave to avoid melt.; Machine: Glowforge Glowforge Pro (co2, 45W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm Clear Acrylic', 6.0, 72.0, 360.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '6mm clear acrylic needs more power than 3mm. Air assist essential to prevent melt-back. Cast acrylic gives polished flame-cut edges.; Machine: Glowforge Glowforge Pro (co2, 45W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Tinted Acrylic', 3.0, 60.0, 1080.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Tinted acrylic cuts cleaner than clear on diode lasers because the pigment absorbs the beam. Air assist prevents melt-back.; Machine: Glowforge Glowforge Pro (co2, 45W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Tinted Acrylic', 0, 20.0, 8400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Tinted acrylic engraves cleanly — pigment absorbs the beam well. Adjust power for contrast.; Machine: Glowforge Glowforge Pro (co2, 45W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Spray Painted Metal', 0, 45.0, 350.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates spray paint to reveal bare metal. Thinner than powder coat so needs less power. Reduce power if paint splatters. Clean with IPA first.; Machine: Glowforge Glowforge Pro (co2, 45W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Powder Coated Steel', 0, 48.0, 300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates powder coat to expose bare metal. Clean with IPA first. No Cermark needed. For bare steel, use fiber laser settings instead.; Machine: Glowforge Glowforge Pro (co2, 45W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated / Powder Coated Steel', 0, 48.0, 300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates powder coat to reveal bare metal beneath. Works on powder coated flat stock and signs. Clean with IPA first. Black powder coat gives highest contrast. No Cermark needed for powder coat removal. For bare steel marking, fiber laser settings apply instead.; Machine: Glowforge Glowforge Pro (co2, 45W)', 'scraped_public', true, 'engrave', 1.0);
