INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock 300gsm', 0, 18.0, 5100.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'CO2 40W on 300gsm cardstock. High speed, low power.; Machine: None K40 CO2 (co2, 35W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 25.0, 15000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'LightBurn forum: K40 users report 250–300 mm/s at 8–9.5 mA (roughly 20–25% of a 40W tube) for anodized aluminum raster engrave. K40 Whisperer equivalent is ~6–8 mA on the dial. Black anodize works well; violet/purple anodize may not absorb the 10.6µm wavelength cleanly. Stock K40 typically has no air assist. Source: forum.lightburnsoftware.com/t/engraving-anodized-type-ii-aluminum-k40-laser/38334 + funinthefalls.gitlab.io/k40/cats/Materials%20and%20settings; Machine: None K40 CO2 (co2, 35W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock 160gsm', 0, 12.0, 3000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Very easy paper cutting for K40. Very low power — stay near 10% to avoid scorching fine detail on intricate cuts.; Machine: None K40 CO2 (co2, 35W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 65.0, 12000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'White engrave on slate. Invert image. K40 gives usable results on stone at this setting. Wipe with damp cloth after.; Machine: None K40 CO2 (co2, 35W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Rubber Stamp Material', 0, 45.0, 7200.0, NULL, NULL, NULL, NULL, NULL, 0.051, NULL, NULL, 'K40 is hugely popular for stamp making. 500 DPI for fine detail. Invert design — dark file areas engrave deep. Great consistent results.; Machine: None K40 CO2 (co2, 35W); DPI: 500', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 22.0, 10800.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'CO2 works beautifully on leather. 22% is a starting point — K40 tube output varies significantly. Always test on scrap.; Machine: None K40 CO2 (co2, 35W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Black Acrylic', 3.0, 60.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'K40 cuts 3mm acrylic cleanly. Remove protective film. Without air assist edges may have slight melt — polish with a heat gun if needed.; Machine: None K40 CO2 (co2, 35W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 65.0, 720.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'K40 without air assist on MDF — watch closely. Good ventilation is essential. MDF fumes are heavy and unpleasant.; Machine: None K40 CO2 (co2, 35W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 30.0, 12000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'K40 Z-travel is limited — ensure precise focus. 200mm/s fill engrave at 30% gives good contrast. A digital readout upgrade helps with repeatability.; Machine: None K40 CO2 (co2, 35W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 55.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'K40 stock tube output varies widely — run a material test first. 55% is a mid-point; adjust for your tube age and condition. Stock bed has no air assist.; Machine: None K40 CO2 (co2, 35W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork 3mm', 3.0, 20.0, 15000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Excellent contrast on natural cork. Cork chars easily — keep power low. Great for wine corks and coasters. No air assist — cork is lightweight and porous.; Machine: None K40 CO2 (co2, 35W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Glass', 0, 25.0, 15000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Apply dish soap or wet newspaper over glass surface before engraving — reduces thermal shock and produces frosted white finish. Wipe clean after. K40 CO2 engraves glass beautifully at low power. Cannot cut glass.; Machine: None K40 CO2 (co2, 35W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic', 3.0, 90.0, 360.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Clear acrylic cuts beautifully with CO2 — polished flame edge. Typical K40 setting: 5–7mm/s at 90% for 3mm clear in one pass. Remove masking immediately after cutting. Colored acrylic varies slightly — black needs a touch less, yellow/orange a touch more. Ventilate well.; Machine: None K40 CO2 (co2, 35W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
