INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Copy Paper 80gsm', 0, 18.0, 11000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Copy paper 80gsm at 40W diode. Very fast, minimal power.; Machine: Longer Longer B1 (diode, 22W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock 300gsm', 0, 25.0, 9000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardstock 300gsm at 40W. Minimal power needed.; Machine: Longer Longer B1 (diode, 22W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('2mm MDF', 2.0, 85.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Two passes through 2mm MDF. MDF cuts fairly cleanly but the fumes from the binders are toxic — run full extraction. Edges will have minor char. At 12W, 3mm MDF typically needs 3-4 passes and results in heavier char.; Machine: Longer Longer B1 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork', 0, 35.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cork engraves with a clean, warm mark at low power. Too much power burns the cork and creates a ragged texture. Great for coasters and placemats. The B1 handles cork well — diode wavelength absorbs nicely into the material.; Machine: Longer Longer B1 (diode, 22W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 40.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Standard single-wall cardboard cuts well at these settings. Good for prototyping before committing to wood or acrylic. Keep an eye on the cut — cardboard can smoulder if you use too many passes.; Machine: Longer Longer B1 (diode, 22W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 30.0, 3000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Kraft paper cuts cleanly at speed. Keep power low to avoid scorching the edges. Great for gift bags, tags, and paper decorations. Use a pin bed or honeycomb to avoid the laser marking the bed surface through the paper.; Machine: Longer Longer B1 (diode, 22W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated Stainless Steel Tumbler', 0, 75.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Removes powder coat to reveal bare metal underneath. Use a rotary attachment and the correct tumbler wrap template for your size. The 12W module has enough power to remove most powder coat coatings in a single pass.; Machine: Longer Longer B1 (diode, 22W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 80.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Diode lasers remove the anodised layer cleanly, revealing bare silver aluminium underneath. High contrast on black or coloured anodised blanks. Works well for dog tags, tumblers, and phone cases. No Cermark needed on anodised aluminium.; Machine: Longer Longer B1 (diode, 22W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 70.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Slate engraves white at these settings. Wipe clean with a damp cloth after to reveal the full contrast. Invert your image so engraved areas appear bright. Slate is forgiving — hard to over-engrave.; Machine: Longer Longer B1 (diode, 22W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 90.0, 150.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 passes to cut through 2mm veg-tan leather. Cutting leather produces unpleasant fumes — ensure good extraction. The B1 handles thin leather well for earrings and keychains but struggles with thick belting leather above 3mm.; Machine: Longer Longer B1 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 45.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Leather engraves beautifully at 45%. Vegetable-tanned leather gives a deep brown mark. Chrome-tanned leather produces a lighter, greyish mark. Always test on a scrap as leather thickness and tanning method affect results significantly.; Machine: Longer Longer B1 (diode, 22W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 55.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Fast raster engrave at 3000mm/min and 55%. The 12W diode gives a warm tan-brown mark on basswood. For fine text keep DPI at 254 — going higher rarely adds visible detail on wood grain.; Machine: Longer Longer B1 (diode, 22W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 90.0, 200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'At 12W, 3mm basswood needs two passes at 90% to cut through reliably. Don''t try to do it in one — you''ll get scorching without a clean break. Air assist keeps the kerf clean and reduces char between passes.; Machine: Longer Longer B1 (diode, 22W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Mirrored Acrylic', 0, NULL, 1400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engrave from the BACK side for a clean mirrored result.; Machine: Longer Longer Ray5 (diode, 5W); DPI: 254', 'scraped_public', true, NULL, 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic (Cast)', 0, NULL, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Longer Longer Ray5 (diode, 5W); DPI: 254', 'scraped_public', true, NULL, 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Maple Plywood', 0, NULL, 80.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 passes at 5W. Dense for this wattage — pin flat.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, NULL, 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Glass', 0, 80.0, 1500.0, NULL, NULL, 0.0, NULL, NULL, NULL, NULL, NULL, 'Glass engraving on 5W diode — use wet paper towel method for best results.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather (Veg-Tan, ~3mm)', 0, 55.0, 2000.0, NULL, NULL, 0.0, NULL, NULL, NULL, NULL, NULL, '5W diode engraves leather at moderate power. Good results on veg-tan.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'engrave', 1.0);
