INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 95.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Longer Longer Ray5 (diode, 5W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Dark Paper', 0, 45.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Dark or black paper cuts cleanly — the dark colour absorbs the diode beam much better than light or white paper. For white paper use higher power (70%) and slower speed. Shadow box paper crafts in dark paper are an excellent application for the Ray5.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Balsa Wood', 0, 80.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2mm balsa cuts in 2 passes at 5W. Balsa''s open cell structure absorbs the beam efficiently making it one of the few materials that cuts reliably at 5W. Use a pin bed to prevent balsa from lifting. Good for model making and architectural scale models.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork', 0, 40.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cork engraves cleanly at 40%. The Ray5 is well-suited to cork — low power is an advantage to prevent over-burning. Great for coasters and trivets. The Ray5 produces results on cork that are indistinguishable from more expensive machines.; Machine: Longer Longer Ray5 (diode, 5W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 85.0, 1200.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Removes anodising to reveal bare aluminium. At 5W results are good but slower than a higher-power machine. No coating needed on anodised aluminium. Dog tags and small anodised pieces work well. For tumblers the Ray5 is too slow for production use but fine for occasional personal projects.; Machine: Longer Longer Ray5 (diode, 5W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 35.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Kraft paper cuts cleanly at moderate speed. Low power prevents edge discolouration. Great for gift tags, labels, and paper decorations. The Ray5 handles paper very well — it''s a good entry point for paper craft makers who want clean, precise cuts.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 85.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Single-wall cardboard cuts in one pass at 5W. Keep power high and speed moderate. Good for stencils, templates, and paper crafts. Corrugated cardboard may need a second pass. Never leave the Ray5 unattended when cutting cardboard — it''s more flammable than wood.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 75.0, 1800.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Slate engraves white at these settings. Invert your image before sending. Even 5W produces good results on slate — the material is very receptive to CO2 and diode wavelengths. Wipe clean with a damp cloth after to see full contrast. One of the easiest materials for a beginner machine.; Machine: Longer Longer Ray5 (diode, 5W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 55.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Leather engraves beautifully at 55% — one of the Ray5''s best use cases. Vegetable-tanned leather gives rich contrast. Even 5W handles leather engraving well because the material absorbs the diode wavelength efficiently. Keep power below 70% to avoid cutting through thin leather.; Machine: Longer Longer Ray5 (diode, 5W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 100.0, 80.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '6 passes at full power and 5W still struggles with 3mm basswood — results are inconsistent with heavy charring. The Ray5 is not a cutting machine. Use it for engraving only, or limit cutting to thin materials like 2mm balsa. A more powerful machine is needed for reliable wood cutting.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'cut', 6.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 65.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Engraving is where the Ray5 shines — 5W is more than adequate for wood surface marking. 65% at 2500mm/min gives a warm brown mark. For lighter marks drop to 50%. At this price point it''s an excellent first laser for engraving keyrings, coasters, and personalised gifts.; Machine: Longer Longer Ray5 (diode, 5W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork 3mm', 3.0, 90.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cork cuts in 2 passes at 5W. Clean edge.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork 3mm', 3.0, 50.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cork is easy for a 5W. Good results for coasters and pot stands.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 3.0, 90.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardboard cuts well at 5W. Good for paper craft and templates.; Machine: Longer Longer Ray5 (diode, 5W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Mirrored Acrylic', 0, NULL, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engrave from the BACK side for a clean mirrored result.; Machine: Monport Monport 40W CO2 (co2, 40W); DPI: 300', 'scraped_public', true, NULL, 1.0);
