INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Walnut', 0, 14.0, 24000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: OMTech OMTech 80W CO2 (co2, 80W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Corrugated Cardboard 4mm', 0, 40.0, 3000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Equivalent to ~50mm/s. Extrapolated from LightBurn forum (forum.lightburnsoftware.com/t/new-to-co2-laser-question-omtech-polar-350-cutting-cardboard/143936) and CAMFive 80W chart. Cardboard is flammable — watch for flare-ups. Air assist essential. Single-wall corrugated at 40% power cuts cleanly; chipboard or double-wall may need 50–60% power or 2 passes. Never leave unattended.; Machine: OMTech OMTech 80W CO2 (co2, 80W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather (Veg-Tan, ~3mm)', 0, 45.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Equivalent to ~10mm/s. From LightBurn forum (forum.lightburnsoftware.com/t/leather-engraving-and-cutting/98726). User reports 10mm/s at 45% on 50W OMTech — scale slightly for 80W by increasing speed to 12–14mm/s (720–840mm/min) at same power. Use 1 pass. Moderate air assist to avoid scorching edges. Thicker leather (4–5mm) may need 2 passes.; Machine: OMTech OMTech 80W CO2 (co2, 80W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather (Veg-Tan, ~3mm)', 0, 25.0, 9000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Equivalent to ~150mm/s. From LightBurn forum (forum.lightburnsoftware.com/t/leather-settings-pictures-attached/31830) and OMTech leather guide (omtech.com/blogs/tips/best-laser-engraving-leather-settings). DPI: 300 LPI. Low power prevents burning through. Vegetable-tanned leather gives best results. Chrome-tanned leather releases toxic fumes — confirm leather type before use. Light air assist only (5–8 PSI).; Machine: OMTech OMTech 80W CO2 (co2, 80W); Air assist: on', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm Baltic Birch Plywood', 0, 80.0, 900.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Equivalent to ~15mm/s. From LightBurn forum (forum.lightburnsoftware.com/t/ruida-64xxg-c02-laser-80w-for-cutting-9mm-deep-into-18mm-plywood/18673) and community LA Hobby Guy (lahobbyguy.com). Voids in cheap plywood require 2 passes; premium birch (Baltic BB grade) often cuts in 1 pass at same settings. High air assist (20+ PSI). Keep power ≤80% to protect tube.; Machine: OMTech OMTech 80W CO2 (co2, 80W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 55.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Equivalent to ~66mm/s. Reported on LightBurn forum (forum.lightburnsoftware.com/t/best-setting-for-engraving-slate/35426) and LA Hobby Guy community (lahobbyguy.com/bb/viewtopic.php?t=2916). Range is 3000–5000mm/min at 45–65%. Air assist OFF — blowing air scatters slate dust unevenly and can prevent the whitening effect. DPI: 300 DPI. Wipe slate clean after engraving.; Machine: OMTech OMTech 80W CO2 (co2, 80W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic (Cast)', 0, 20.0, 24000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Equivalent to ~400mm/s. High speed + low power for cast acrylic produces a bright frosted white engrave. DPI: 254–300 LPI. Source: LightBurn forum (forum.lightburnsoftware.com/t/acrylic-cutting-and-engraving/68186) and OMTech knowledge base (omtech.com/blogs/knowledge/material-settings-for-laser-engravers). Reduce power if engraving goes too deep.; Machine: OMTech OMTech 80W CO2 (co2, 80W); Air assist: on', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic (Cast)', 0, 65.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Equivalent to ~20mm/s. Community consensus from LightBurn forum (forum.lightburnsoftware.com/t/omtech-80w-laser-won-t-cut-through-acrylic/110337) and CNCZone reports 18–22mm/s at 60–70% for clean single-pass cuts on cast acrylic. Use LOW air pressure (8–12 PSI) to avoid frosting the edge. Extruded acrylic may need 1 extra pass.; Machine: OMTech OMTech 80W CO2 (co2, 80W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('12mm MDF', 12.0, 72.0, 720.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '12mm MDF at 80W. Single pass but generates very heavy fumes — run strong ventilation. Slight edge char is normal for this thickness.; Machine: OMTech OMTech 80W CO2 (co2, 80W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Ceramic Mug', 0, 50.0, 18000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Cermark on mugs with rotary. 80W needs lower power than smaller machines. Thin even coats of Cermark work better than thick ones.; Machine: OMTech OMTech 80W CO2 (co2, 80W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Walnut Plywood', 3.0, 35.0, 2100.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Walnut at 80W. Low power, high speed. Premium results for high-end products.; Machine: OMTech OMTech 80W CO2 (co2, 80W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock', 0, 15.0, 4800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardstock on Polar. Good for card blanks, gift tags, invitations.; Machine: OMTech OMTech Polar (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Paper', 0, 12.0, 6000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Paper on OMTech Polar 30W. Compact CO2 handles paper well at low power.; Machine: OMTech OMTech Polar (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Photopolymer Stamp Blank', 0, 48.0, 6000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '500 DPI gives finer stamp detail. Deeper engrave = higher relief = crisper impression. Always test on scrap first.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 500', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('9mm Birch Plywood', 0, 25.0, 6000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '9mm birch engraves cleanly. For deeper relief reduce speed or raise power.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('9mm Birch Plywood', 9.0, 85.0, 150.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '9mm birch requires many passes on diode — CO2 is recommended at this thickness. Pin material flat. Air assist on all passes.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 4.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('5mm Plywood', 0, 24.0, 7200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '5mm plywood engraves well. Deeper relief: reduce speed or increase power slightly.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('5mm Plywood', 5.0, 72.0, 420.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '5mm plywood requires multiple passes on diode — pin material flat between passes. Air assist essential.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('2mm Basswood Plywood', 0, 12.0, 21000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2mm basswood engraves with deep contrast. 300 DPI is the sweet spot — higher increases burn time significantly.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('2mm Basswood Plywood', 2.0, 38.0, 1320.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2mm basswood cuts in a single pass on most diode lasers. Air assist keeps the cut clean and reduces char.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm Clear Acrylic', 0, 28.0, 4800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'CO2 wavelength is absorbed by clear acrylic — diode lasers pass straight through. Keep power low for engrave to avoid melt.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm Clear Acrylic', 6.0, 80.0, 240.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '6mm clear acrylic needs more power than 3mm. Air assist essential to prevent melt-back. Cast acrylic gives polished flame-cut edges.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Tinted Acrylic', 3.0, 68.0, 840.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Tinted acrylic cuts cleaner than clear on diode lasers because the pigment absorbs the beam. Air assist prevents melt-back.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Tinted Acrylic', 0, 22.0, 7200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Tinted acrylic engraves cleanly — pigment absorbs the beam well. Adjust power for contrast.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Spray Painted Metal', 0, 50.0, 280.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates spray paint to reveal bare metal. Thinner than powder coat so needs less power. Reduce power if paint splatters. Clean with IPA first.; Machine: OMTech OMTech Polar (co2, 30W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Powder Coated Steel', 0, 55.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ablates powder coat to expose bare metal. Clean with IPA first. No Cermark needed. For bare steel, use fiber laser settings instead.; Machine: OMTech OMTech Polar (co2, 30W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Mirrored Acrylic', 0, NULL, 350.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engrave from the BACK side of the sheet for a clean mirrored result.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, NULL, 1.0);
