INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel', 0, 62.0, 10800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Apply Cermark spray, let dry, laser, wipe off. Permanent mark.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
