INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 22.0, 21000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, '254 DPI engrave at 22% gives clean lines without excessive burning into the grain. Use LightBurn''s Stucki dithering for photo engraves — the tight grain of Baltic birch holds fine detail well.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 72.0, 1080.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Baltic birch is more consistent than standard plywood. At 72% and 18mm/s it cuts cleanly. The void-free core means fewer failed cuts mid-sheet. Great for jig templates and detailed puzzle pieces.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Walnut Plywood', 3.0, 78.0, 840.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Walnut is denser than basswood so it needs slightly more power or slower speed. At 78% and 14mm/s it cuts through cleanly with minimal char. The natural dark grain means engraving shows beautiful contrast without burning.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 20.0, 6000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Clean cuts on kraft paper at high speed and low power. Ideal for wedding invites, paper lanterns, and gift bags. Use a honeycomb or pin bed to support the paper without scorching.; Machine: OMTech OMTech Polar (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 30.0, 4800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Corrugated cardboard cuts cleanly at speed. Keep power low to avoid ignition — cardboard is highly flammable. Never leave the machine unattended. Great for prototyping jig designs before cutting the real material.; Machine: OMTech OMTech Polar (co2, 30W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm MDF', 6.0, 80.0, 720.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Single pass through 6mm MDF at 80%. MDF produces more fumes than plywood so ensure your exhaust is running at full capacity. Edges will have some char — sand lightly if painting. Avoid cutting MDF without air assist.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 60.0, 18000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Bright white engrave on slate. Invert your image in LightBurn so the engraved areas appear light. Wipe the slate with a damp cloth after engraving to remove dust and reveal full contrast. No coating needed.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 18.0, 21000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Rich dark brown mark at 18%. Leather is very easy to overpower with CO2 — start low and step up in 2% increments. Vegetable-tanned leather gives better contrast than chrome-tanned. Remove any protective coating first.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic', 3.0, 15.0, 21000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Frosted finish at 15% and 350mm/s. CO2 engraves acrylic cleanly without melting the surface. For photos, use a dithered image (Newsprint or Stucki in LightBurn) and invert for a light-on-dark result.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic', 3.0, 75.0, 720.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Slow and steady gets flame-polished edges on clear acrylic. Remove the protective film on the top only — leave the bottom film on to protect your bed. Good ventilation is critical; acrylic fumes are harmful.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 20.0, 18000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Fast raster at 300mm/s and 20% — the CO2 beam gives a warm brown engrave without burning through. Drop to 15% for lighter marks on pale basswood. Grain direction affects contrast so rotate your artwork 90° and compare.; Machine: OMTech OMTech Polar (co2, 30W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 70.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Single clean pass at 70% — pushing higher causes edge charring without improving cut speed on this 30W tube. Air assist is essential to prevent flame and keep edges clean. Always do a test strip when opening a new sheet as density varies between batches.; Machine: OMTech OMTech Polar (co2, 30W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Mirrored Acrylic', 0, NULL, 450.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engrave from the BACK side for a clean mirrored result.; Machine: OMTech OMTech Polar+ 55W (co2, 55W); DPI: 300', 'scraped_public', true, NULL, 1.0);
