INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Leather', 0, 65.0, 3500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Sculpfun Sculpfun S10 Pro (diode, 10W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 95.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 92.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Two passes through 3mm Baltic birch. The void-free core gives more consistent results than standard plywood at the same settings. Air assist reduces char significantly. The S10 Pro handles Baltic birch well for jig templates and small production runs.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated Stainless Steel Tumbler', 0, 75.0, 2200.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Removes powder coat in one pass. Use a rotary attachment and calibrate steps-per-mm in LightBurn. Clean with IPA before engraving. The S10 Pro''s 10W is sufficient for most powder coat brands in a single pass. Ensure the tumbler is level and balanced on the rotary.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork', 0, 32.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cork engraves cleanly at low power. At 10W, 32% is the sweet spot — higher power burns through the surface texture. Great for coasters and trivets. The S10 Pro produces results on cork indistinguishable from much more expensive machines.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 50.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Single-wall cardboard cuts cleanly at moderate power. Good for rapid prototyping before committing to wood or acrylic. Keep power under 65% to reduce ignition risk. Never leave the machine unattended when cutting cardboard.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 78.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Removes anodising cleanly. No Cermark needed on anodised aluminium — the diode wavelength strips the layer efficiently. Great for dog tags, tumblers, and keyrings. Use a rotary attachment for cylindrical pieces.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 70.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Bright white engrave on slate. Invert your image before sending. The S10 Pro produces excellent slate results — one of the most satisfying materials for diode lasers. Wipe clean with a damp cloth after to reveal full contrast.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 45.0, 3500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Rich dark engrave on vegetable-tanned leather at 45%. The 10W module handles leather engraving excellently. Keep power below 60% to avoid cutting through thin leather. Test on chrome-tanned leather separately as it gives lighter, greyer marks.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 50.0, 4500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Fast raster engrave at 4500mm/min and 50%. The S10 Pro''s improved beam quality over the S9 gives slightly sharper engraves on wood. For photo engraving use Stucki dithering and drop to 40%. Consistent warm brown marks across the whole sheet.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 90.0, 300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Two passes at 90% cuts 3mm basswood cleanly. The S10 Pro''s 10W module is a step up from the original S9 with better beam quality. Air assist significantly reduces char between passes. A solid all-round engraver and light cutter for the price.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 85.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'MDF cuts cleanly with 10W + air assist in 3 passes. Multiple faster passes give cleaner edges than 1 slow pass. Heavy fumes — ventilate well. Air assist is critical for MDF.; Machine: Sculpfun Sculpfun S10 Pro (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 18.0, 4000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Kraft paper on S30 Pro.; Machine: Sculpfun Sculpfun S30 Pro (diode, 33W)', 'scraped_public', true, 'cut', 1.0);
