INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Plywood', 0, 95.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Sculpfun Sculpfun S6 Pro (diode, 6W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Leather', 0, 70.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Sculpfun Sculpfun S6 Pro (diode, 6W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 95.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Sculpfun Sculpfun S6 Pro (diode, 6W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Dark Paper', 0, 45.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Dark or black card cuts cleanly — the dark colour absorbs the diode beam far better than white paper. Shadow box artwork in black card is an excellent fit for the S6 Pro''s capabilities. Intricate paper-cut designs work well at slow speed with steady hands on the honeycomb.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Balsa Wood', 0, 80.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2mm balsa cuts in 2 passes at 6W. Balsa''s open cellular structure absorbs the beam efficiently — one of the few materials the S6 Pro cuts reliably. Good for model making and architectural scale models where thin precise cuts are needed.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W)', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 38.0, 1800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Kraft paper cuts cleanly at moderate speed. Low power prevents edge browning. Great for gift tags and paper decorations. The S6 Pro handles paper very well and is a good machine for paper crafters who are starting out with lasers.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 85.0, 700.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Single-wall corrugated cardboard cuts in one pass. Keep power high and don''t slow down further — at 6W you need all the power available for clean cuts. Good for stencils and prototyping. Never leave unattended when cutting cardboard.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 85.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Removes anodising at 85%. At 6W it''s slower than higher-power machines but the result is the same — bare aluminium revealed cleanly. No coating needed. Good for occasional dog tags and keyrings, but not fast enough for high-volume tumbler production.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 100.0, 120.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '4 passes at full power barely cuts 3mm basswood — results are unreliable with heavy charring. The S6 Pro is an engraving machine, not a cutter. Limit cutting to 2mm balsa or thin card. For wood cutting, a 20W+ machine is the right tool.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W)', 'scraped_public', true, 'cut', 4.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 60.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'The S6 Pro''s 6W module engraves wood cleanly. 60% at 3000mm/min gives a warm brown mark. A solid entry-level engraver for personalised gifts and small craft items. For darker marks increase to 75%. The S6 Pro punches above its weight for engraving given its low price.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Black Acrylic', 3.0, 100.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Opaque/cast black acrylic only — clear acrylic passes straight through 450nm diode. The S6 Pro needed 10 passes at 600mm/min vs S6 needing 16, per hobbylasercutters review. Constant power mode. Remove protective paper after cut.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W)', 'scraped_public', true, 'cut', 10.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 60.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Smooth uniform density — good for signs and plaques. Consistent material means predictable results. Slightly higher power than basswood needed. Dynamic power mode.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 80.0, 200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Community-tested: 200mm/min, 80%, 4 passes gives clean result in ~1.5h. Alternatively: 600mm/min, 70%, 10 passes for less charring in ~1.2h. Air assist upgrade cuts passes by ~1/3. MDF produces heavy fumes — ventilate well.; Machine: Sculpfun Sculpfun S6 Pro (diode, 6W)', 'scraped_public', true, 'cut', 4.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 45.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Kraft paper on S9.; Machine: Sculpfun Sculpfun S9 (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock', 0, 65.0, 800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardstock on S9. May need slight defocus for cleaner edges.; Machine: Sculpfun Sculpfun S9 (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Paper', 0, 50.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Paper on Sculpfun S9. 10W needs more power % but still single pass.; Machine: Sculpfun Sculpfun S9 (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel', 0, 100.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Slower pass for deeper Cermark bond on stainless. Multiple thin coats of spray gives better adhesion.; Machine: Sculpfun Sculpfun S9 (diode, 10W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Glass', 0, 45.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Slower pass for finer detail on glass. Mask surface with wet tissue to improve result.; Machine: Sculpfun Sculpfun S9 (diode, 10W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Marble Tile', 0, 80.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher speed with full power for faster throughput on marble tile engravings.; Machine: Sculpfun Sculpfun S9 (diode, 10W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate (coaster)', 0, 85.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Higher DPI for fine detail and photo work on slate coasters.; Machine: Sculpfun Sculpfun S9 (diode, 10W); DPI: 400', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Mirrored Acrylic', 0, NULL, 2600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Engrave from the BACK side for a clean mirrored result.; Machine: Sculpfun Sculpfun S9 (diode, 10W); DPI: 254', 'scraped_public', true, NULL, 1.0);
