INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 45.0, 2100.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Thunder Thunder Laser Nova 35 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 15.0, 24000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, '100W CO2 — far less power needed than for cutting. thunderlaserusa.com blog on metal engraving recommends high speed + low power to avoid burning through the anodize layer. 400 mm/s at 15% power is consistent with the general CO2 principle: scale speed up and power down as wattage increases above 60W. Background engraving examples at 500 speed / 20–40% power also noted. Source: thunderlaserusa.com/blog/how-to-engrave-on-metal-with-a-thunder-laser-nova-35 + microfluidics.cnsi.ucsb.edu/wiki/doku.php?id=thunderlaser_nova35; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); Air assist: on', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 22.0, 15000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardboard cuts at very high speed and low power. The Nova 35''s large bed makes it excellent for cutting corrugated packaging prototypes at full size. Watch for fire at these speeds — keep your hand near the emergency stop when cutting cardboard.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 52.0, 3300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Baltic birch cuts fast and reliably on the Nova 35. The combination of consistent plywood and reliable machine means near-zero waste cuts. Popular with laser businesses running puzzle pieces, wooden toys, and decorative panels at volume.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Walnut Plywood', 3.0, 55.0, 3000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Walnut plywood cuts with minimal char and clean edges. At production speeds on the Nova 35, walnut is fast and reliable — a full sheet of 30 name signs in under 20 minutes. The large bed is ideal for batching high-value hardwood items.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm MDF', 6.0, 70.0, 1800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '6mm MDF in one clean pass. The Thunder Laser''s robust exhaust system handles MDF fumes well but always run additional extraction when using MDF in production quantities. Edge quality is excellent with minimal char compared to lower-powered machines.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 55.0, 24000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Very fast slate engraving on the large bed — engrave multiple slate coasters in a single job. The 900×600mm bed fits 12-16 standard coasters in one pass. Consistent bright white result across the whole sheet with the Nova 35''s even power distribution.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 18.0, 24000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'At 60W even 18% is plenty for leather — the Nova 35 can engrave leather very fast. For large leather goods (bags, belts, portfolios) the 900×600mm bed is a genuine advantage. Test at 15% first; the high-powered tube can surprise you on thin leather.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('10mm Plywood', 10.0, 80.0, 900.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '10mm plywood in a single pass — this is where the Nova 35 earns its keep over smaller machines. Air assist is critical to prevent the kerf from igniting deep in the cut. Focus on the top surface; consider splitting focus to midpoint for very consistent results on the thickest boards.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic', 3.0, 15.0, 27000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Crisp frosted engrave at 15% and 450mm/s. The 60W tube at 15% is equivalent to about 30% on a 20W machine. The large bed makes it practical to engrave full-sheet acrylic signage in a single job. Use LightBurn''s ''constant power'' mode for even fills.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Clear Acrylic', 3.0, 55.0, 2700.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Flame-polished acrylic cuts at production speed. The Nova 35''s consistent power delivery produces even polish across a 600mm wide cut — no variation between the start and end of a long cut that''s common on machines with inferior PSUs.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm Basswood Plywood', 6.0, 65.0, 2100.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '6mm basswood in one pass — the 60W tube handles this with ease. The Nova 35''s Z-table lifts to accommodate thicker material and maintains consistent focus throughout the cut. Air assist is integrated and essential for keeping the kerf clean on thick material.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 22.0, 24000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Very fast raster at 400mm/s. At 60W, 22% gives a warm medium mark without burning. The Nova 35 engraves large flat items extremely quickly — a full 900mm wide plaque in under 5 minutes. Use Thunder Laser''s LightBurn profile for correct speed/power calibration.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 50.0, 3600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'The Nova 35''s 60W tube makes 3mm basswood trivial — 50% power is more than enough. Pushing higher causes unnecessary edge charring. The rigid aluminium frame and Z-table give consistent focus across the full 900×600mm bed. Run a power/speed matrix test on new batches of plywood.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Bamboo Cutting Board', 0, 28.0, 21000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Beautiful contrast on bamboo. Great for gift and personalisation businesses.; Machine: Thunder Thunder Laser Nova 35 (co2, 100W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
