INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 95.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Two Trees Two Trees TS2 (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated Stainless Steel Tumbler', 0, 70.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Removes powder coat in one pass to reveal bare metal. Use a rotary attachment and calculate the correct steps-per-mm for the TS2 rotary (typically around 80-100 for a wheel rotary). Clean the tumbler with IPA before engraving and ensure it''s centred on the rotary.; Machine: Two Trees Two Trees TS2 (diode, 10W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('2mm MDF', 2.0, 85.0, 200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Two passes through 2mm MDF at 10W. MDF fumes are toxic — run extraction at full capacity. Air assist significantly reduces edge char on MDF cuts. For 3mm MDF add a third pass; at 10W thick MDF is challenging and edges will have noticeable char.; Machine: Two Trees Two Trees TS2 (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork', 0, 30.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cork engraves cleanly at low power and high speed. Too much power burns the surface and creates rough marks. The TS2 handles cork coasters and place settings well. Engrave multiple coasters in a single batch job using the TS2''s array feature in LightBurn.; Machine: Two Trees Two Trees TS2 (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 75.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Removes the anodised layer to reveal bright aluminium. No coating needed — diode lasers remove anodising cleanly. Great for dog tags, tumblers, and branded accessories. Use a rotary attachment for cylindrical items like tumblers.; Machine: Two Trees Two Trees TS2 (diode, 10W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 0, 45.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardboard cuts cleanly at moderate speed. Keep power below 60% to reduce ignition risk. Good for packaging prototypes and box templates. The TS2''s larger 450×450mm bed means you can cut full A3-sized flat pack designs in one job.; Machine: Two Trees Two Trees TS2 (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 65.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Clean white engrave on slate. Invert your image before engraving. Even at 10W the TS2 produces excellent results on slate — one of the easiest materials to get right with a diode laser. Wipe clean with a damp cloth after the job.; Machine: Two Trees Two Trees TS2 (diode, 10W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 90.0, 150.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 passes for 2mm veg-tan leather. Leather cutting produces strong fumes — good extraction is essential. The TS2 handles thin leather well for earrings and keychains. Thicker belting leather (3mm+) is better suited to a CO2 laser.; Machine: Two Trees Two Trees TS2 (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 45.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Rich dark mark on vegetable-tanned leather. 45% at 3000mm/min avoids cutting through while still giving excellent depth. Chrome-tanned leather needs slightly more power for the same visual contrast. Always test on a leather scrap first.; Machine: Two Trees Two Trees TS2 (diode, 10W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 50.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Fast raster engrave at 4000mm/min. The 10W diode gives a warm brown mark at 50%. For darker marks increase to 65%. The TS2''s 450×450mm bed is good sized — batch multiple pieces in one job for efficient engraving runs.; Machine: Two Trees Two Trees TS2 (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 90.0, 300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Two passes needed at 10W for reliable clean cuts through 3mm basswood. Air assist is an add-on for the TS2 — it dramatically improves cut quality and reduces char. Without air assist expect heavier edge burning and inconsistent cuts on knot areas.; Machine: Two Trees Two Trees TS2 (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 100.0, 150.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '4 passes at 10W for MDF. Slow but effective. Air assist upgrade highly recommended for MDF.; Machine: Two Trees Two Trees TS2 (diode, 10W)', 'scraped_public', true, 'cut', 4.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork 3mm', 3.0, 80.0, 600.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Easy cork cut. Clean edge.; Machine: Two Trees Two Trees TS2 (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
