INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Basswood', 0, 95.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: Woxcker Woxcker L2 MAX (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel', 0, 50.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Faster pass for simple logos or large fills. May leave slight paint haze — a second pass at same settings cleans it. Use if 2000mm/min setting feels too slow for large jobs.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); Air assist: on', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Black Acrylic', 3.0, 100.0, 100.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Opaque/cast black acrylic only. Use Constant Power mode in LightBurn. Focus 1–2mm below surface. Clear acrylic is not suitable — 450nm diode passes straight through it.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 10.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork 3mm', 3.0, 70.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Multiple passes cleaner than one slow pass. Air assist recommended to prevent flare-ups in porous cork.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cork 3mm', 3.0, 30.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Cork chars easily — keep power low. Lovely contrast at low settings. Test on scrap first.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardboard', 3.0, 75.0, 700.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Fast clean cut. Skip air assist on cardboard — it can cause flare-ups. Watch closely.; Machine: Woxcker Woxcker L2 MAX (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 30.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.08, NULL, NULL, 'Removes anodized coating — reveals bare metal underneath. High contrast result. Wipe with microfiber cloth after to reveal detail. Works best on black anodized; gold/silver anodize may need more power. Does NOT work on bare (non-anodized) aluminum.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); DPI: 318', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 100.0, 2000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Bright white mark on black slate. Invert your image in LightBurn. No air assist — it scatters debris onto the lens. Wipe surface with damp cloth after. Use Stucki or Jarvis dithering for photos.; Machine: Woxcker Woxcker L2 MAX (diode, 10W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 100.0, 300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2–3mm veg-tan. Keep speed moderate — too slow scorches the oils. Air assist helps edge quality.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 45.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Clean dark mark on veg-tan leather. Power varies by hide thickness — test on scrap first. Veg-tan only; never chrome-tanned leather.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 100.0, 200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Glue layers absorb differently — 3 passes. Air assist on. Check flatness of sheet before long cuts.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Baltic Birch Plywood', 3.0, 65.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Watch for glue layers causing inconsistency. Consistent with even pressure on the material.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 100.0, 250.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'MDF chars heavily — air assist is critical. 3 passes. Multiple fast passes give cleaner edges than one slow pass.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 3.0, 55.0, 3500.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Uniform density — no grain surprises. Good for signage and name plaques.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 100.0, 400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 passes at full power. Air assist greatly reduces char on edges. Ensure material is flat to the bed.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Basswood Plywood', 3.0, 60.0, 3000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Good fill engrave. Forgiving material. Bump to 70% for darker result. Run a material test grid first.; Machine: Woxcker Woxcker L2 MAX (diode, 10W); DPI: 254', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Kraft Paper', 0, 22.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Kraft paper. Lower power than cardstock as kraft is thinner.; Machine: xTool xTool D1 Pro (diode, 20W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock', 0, 12.0, 5000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Score cardstock for clean fold lines.; Machine: xTool xTool D1 Pro (diode, 20W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock', 0, 35.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cardstock cut. Slight char on edges at higher power - keep speed up.; Machine: xTool xTool D1 Pro (diode, 20W)', 'scraped_public', true, 'cut', 1.0);
