INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 90.0, 24000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'IR module. Ablates slate surface cleanly.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Copper', 0, 50.0, 90000.0, NULL, NULL, 0.0, NULL, NULL, NULL, NULL, NULL, '0; Machine: xTool xTool F1 (fiber, 2W); Air assist: on', 'scraped_public', true, 'engrave', 60.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Black Anodized Aluminum', 0, 30.0, 120000.0, NULL, NULL, 0.0, NULL, NULL, NULL, NULL, NULL, '0; Machine: xTool xTool F1 (fiber, 2W); Air assist: on', 'scraped_public', true, 'engrave', 40.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated / Powder Coated Steel', 0, 100.0, 18000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Powder coat is easier to ablate than bare metal. 2W can remove coating to expose steel, but results depend heavily on coating thickness and color. Thin coatings work in 1–2 passes; thick industrial coats may need more. xTool LightBurn forum painted tumbler data used as reference. | Freq: 40kHz, line interval: 0.05mm; Machine: xTool xTool F1 (fiber, 2W)', 'scraped_public', true, 'mark', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Titanium', 0, 100.0, 18000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Titanium anneals at lower energy threshold than stainless — 2W can produce visible marks and limited color effects. Color range will be narrower than 20W MOPA. xTool confirms IR module compatibility with titanium. Start at 100% power, 300mm/s, and adjust for color. Pulse width not adjustable on F1. | Freq: 50kHz, line interval: 0.04mm; Machine: xTool xTool F1 (fiber, 2W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Copper', 0, 100.0, 6000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Copper is highly reflective at 1064nm and 2W is at the extreme limit. Results will be very light/minimal. Not a recommended application for the 2W F1 — the F1 Ultra (20W fiber) is the appropriate machine for copper. Included here as a best-effort starting point only. | Freq: 30kHz, line interval: 0.03mm; Machine: xTool xTool F1 (fiber, 2W)', 'scraped_public', true, 'mark', 5.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Brass', 0, 100.0, 12000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2W fiber can produce a light surface mark on brass. Deep engraving is not realistic at 2W. Multiple passes required. The F1 Ultra (20W) is recommended for brass. Use as a marking/ID tool only. xTool material guide confirms brass compatibility with IR module. | Freq: 40kHz, line interval: 0.04mm; Machine: xTool xTool F1 (fiber, 2W)', 'scraped_public', true, 'mark', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Black Anodized Aluminum', 0, 100.0, 9000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'machinesformakers.com lists xTool F1 Lite (also 2W class) black anodized aluminum at 150mm/s 40% power. Scaling to full 100% power may allow slightly faster speed; start at 150mm/s and test. One of the better use cases for the 2W fiber. | Freq: 50kHz, line interval: 0.05mm; Machine: xTool xTool F1 (fiber, 2W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 100.0, 90000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Anodized aluminum is one of the best materials for the F1 2W — coating ablates cleanly at relatively high speed. The F1 Ultra (20W fiber) uses 2000mm/s at 75% for green anodize; 2W F1 needs lower speed and max power. xTool machinesformakers.com F1 Ultra anodize data scaled conservatively for 2W. | Freq: 50kHz, line interval: 0.05mm; Machine: xTool xTool F1 (fiber, 2W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Tumbler', 0, 100.0, 18000.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Requires RA2 Pro rotary attachment. At 2W, tumbler engraving is possible but requires slow speed and multiple passes for decent contrast. xTool Silhouette School blog and support article confirm IR for stainless tumbler. Result will be lighter than 20W machine. | Freq: 40kHz, line interval: 0.05mm; Machine: xTool xTool F1 (fiber, 2W)', 'scraped_public', true, 'engrave', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel', 0, 100.0, 24000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2W fiber is very low power — 100% power + multiple passes required for any visible mark on stainless. Result is light gray mark, not deep black. xTool official: IR (2W) is ideal for marking stainless. xTool F1 max speed 4000mm/s, freq range 30–60kHz. Expect lighter result than 20W+ MOPA. Pulse width not user-adjustable on F1. | Freq: 50kHz, line interval: 0.05mm; Machine: xTool xTool F1 (fiber, 2W)', 'scraped_public', true, 'mark', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Tumbler', 0, 78.0, 2400.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Uncoated stainless tumblers and water bottles. Black oxidation mark — dishwasher safe when fully cured (24hrs). Use rotary attachment for curved surfaces. Adjust focus to the top of the surface arc. Single pass; increase power to 85% for a bolder mark.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Spray Painted Metal', 0, 55.0, 3500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Removes spray paint or brush-applied paint from steel or aluminium to reveal bare metal below. High speed and moderate power for clean coating removal without marking the base metal. Popular technique for signs, trophies, and personalised tools. Works on most paint colours.; Machine: xTool xTool F1 (fiber, 2W); DPI: 254', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Aluminum Keychain', 0, 88.0, 1300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Bare aluminum keychain blanks — common in budget blanks. Mark is a dark ablated surface. Needs more power than anodized equivalent. Clean with IPA before engraving. Results vary slightly between alloy grades (6061 marks better than 1100 series).; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Keychain', 0, 80.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Standard stainless keychain blanks and fobs. Identical settings to bare stainless. Clip or tape blanks into jig for batch runs. Single pass for a clean black mark. Polished finish gives better photo-quality contrast than brushed.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Knife Blade', 0, 82.0, 1800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Bare stainless knife blade engraving. Dark oxidation mark — permanent, food-safe when sealed. Use low DPI (254) for bold logos; 300–500 DPI for fine text. Secure blade firmly — any movement on a curved surface will defocus. Mask handle with tape.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Black Oxide Stainless Steel', 0, 65.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Black oxide coated stainless (knives, tools, watch parts). Removes the black oxide coating to reveal bright silver stainless beneath — striking contrast. Great for knife blades, EDC tools, and hardware. Check blade is demagnetised before securing in jig.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Nickel Plated Steel', 0, 75.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Common in budget dog tag and keychain blanks. Nickel plating engraves similarly to chrome — IR removes plating in marked area. Contrast can be variable depending on plating thickness. Single pass; add a second if mark is weak.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Powder Coated Steel', 0, 65.0, 2800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Powder coated steel panels, brackets, and hardware. Removes coating cleanly. Very similar settings to powder coated aluminium — try 62% power first and step up if mark is incomplete. Good for industrial labels and tool personalisation.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Powder Coated Aluminum', 0, 62.0, 3000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Removes powder coat to expose bare aluminum beneath — high contrast matte-to-metal look. Works on any powder coat colour. Commonly used for tumblers, keychains, water bottles, and signage panels. No need to remove paint first.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Zippo Lighter (Chrome)', 0, 72.0, 2200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Standard Zippo and windproof lighter bodies. Removes chrome coating cleanly to reveal base steel. Good contrast for names, logos, and designs. Secure lighter in jig — even small movement blurs detail. Wipe with dry cloth after engraving.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Chrome Plated Steel', 0, 85.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Deeper mark through chrome plating into base steel. Good for permanent ID on tools and hardware. Mark may show slight colour variation at chrome/steel boundary. Single pass sufficient for most plating thicknesses.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Chrome Plated Steel', 0, 70.0, 2500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Chrome plated steel — Zippo-style lighters, tool handles, and hardware. IR removes chrome plating in the marked area to expose steel below. Contrast depends on plating thickness. Start with a test mark and adjust power. Thicker chrome needs more power.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Black Anodized Aluminum Dog Tag', 0, 48.0, 4000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Black anodized bone or rectangle dog tags — removes anodizing to reveal bright silver aluminum beneath. Very high contrast. High speed for throughput — good for batch personalisation. Ideal for pet ID tags sold on Etsy.; Machine: xTool xTool F1 (fiber, 2W); DPI: 254', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Aluminum Dog Tag', 0, 88.0, 1200.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Bare aluminum dog tag blanks (not anodized). Mark is darker and more permanent than on anodized. Higher power and slower speed than anodized tags. Clean surface with IPA before running. Pet tags and keychains.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Dog Tag', 0, 90.0, 1200.0, NULL, NULL, NULL, NULL, NULL, 0.051, NULL, NULL, 'Deep engrave for premium pet ID or military replica dog tags. 2 passes gives a debossed look. More readable than surface marks if the tag will be worn and handled. 500 DPI for sharp text.; Machine: xTool xTool F1 (fiber, 2W); DPI: 500', 'scraped_public', true, 'engrave', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Dog Tag', 0, 80.0, 2000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Standard 50×28mm dog tag blanks. Black oxidation mark — single pass. Very fast for batch runs. Use jig to hold multiple tags. Works on military-spec and pet ID tags alike. Brushed finish gives better contrast than polished.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Business Card', 0, 90.0, 900.0, NULL, NULL, NULL, NULL, NULL, 0.051, NULL, NULL, 'High-detail engraving on stainless business cards for a premium tactile finish. 2 passes at 500 DPI produces a clearly recessed mark. Slower than marking but gives a noticeably deeper result. Good for logos, names, and QR codes.; Machine: xTool xTool F1 (fiber, 2W); DPI: 500', 'scraped_public', true, 'engrave', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Business Card', 0, 80.0, 1800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0.3–0.5mm stainless business cards. Deep black oxidation mark — permanent and corrosion resistant. Single pass is sufficient. Clamp or tape card flat — any flex affects focus and mark quality. Works equally well on brushed and mirror-polished finish.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Bare Aluminum', 0, 95.0, 800.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Deep ablative engrave into raw aluminum. 2 passes at near max power for a visible groove. Good for nameplates and signage where a tactile mark is needed. Expect some burr on edges — clean with a fine file or brass brush.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'engrave', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Bare Aluminum', 0, 85.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Raw uncoated aluminum — harder to mark than anodized as there is no coating to remove. IR oxidation mark. Higher power and slower speed than anodized. Result is a dark grey/black surface mark. Clean surface first with IPA.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Silver Jewellery', 0, 50.0, 1000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Surface mark on sterling silver. 50% power gives visible dark mark. Test on scrap piece first.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel', 0, 90.0, 1200.0, NULL, NULL, NULL, NULL, NULL, 0.051, NULL, NULL, 'High-detail QR codes and barcodes on stainless. 2 passes at 500 DPI for scannable depth.; Machine: xTool xTool F1 (fiber, 2W); DPI: 500', 'scraped_public', true, 'engrave', 2.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Brass', 0, 80.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Clean dark mark on raw brass. Great for trophies and plaques. Polished brass needs slightly more power.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Gold-Filled Jewellery', 0, 40.0, 1500.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Gentle surface mark on gold-filled pieces. Test on scrap — too much power damages plating.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated Stainless Steel Tumbler', 0, 75.0, 2500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Removes powder coat to reveal bare metal underneath. Clean contrast. Use rotary attachment for tumblers.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Titanium', 0, 70.0, 1500.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Colour marking on titanium — varies with speed. Lower speed = warmer colours (gold/purple). Test speed to get desired colour.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Anodized Aluminum', 0, 50.0, 4000.0, NULL, NULL, NULL, NULL, NULL, 0.085, NULL, NULL, 'Removes anodizing to reveal bare aluminum. High contrast. Works on all anodized colours.; Machine: xTool xTool F1 (fiber, 2W); DPI: 300', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Coated / Powder Coated Steel', 0, 75.0, 108000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Removes powder coat layer. Clean mark on bare steel underneath.; Machine: xTool xTool F1 Ultra (Fiber) (fiber, 2W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate', 0, 95.0, 36000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'White frost on slate. Stone needs near-max power at 2W.; Machine: xTool xTool F1 Ultra (Fiber) (fiber, 2W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Aluminum Dog Tag', 0, 75.0, 168000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Fast batch dog-tag marking with galvo head.; Machine: xTool xTool F1 Ultra (Fiber) (fiber, 2W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Black Oxide Stainless Steel', 0, 88.0, 96000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Bright silver contrast on black oxide finish.; Machine: xTool xTool F1 Ultra (Fiber) (fiber, 2W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Knife Blade', 0, 90.0, 90000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Permanent blade mark. 2W leaves clean edge without over-heating.; Machine: xTool xTool F1 Ultra (Fiber) (fiber, 2W)', 'scraped_public', true, 'mark', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Stainless Steel Business Card', 0, 90.0, 90000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Near-max power for steel cards. 0.05mm fill spacing for solid fill.; Machine: xTool xTool F1 Ultra (Fiber) (fiber, 2W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Bare Aluminum', 0, 78.0, 168000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'White mark on raw aluminum. 2W galvo speed compensates for low power.; Machine: xTool xTool F1 Ultra (Fiber) (fiber, 2W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Powder Coated Aluminum', 0, 90.0, 84000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Removes powder coat from aluminum. Full power area at 2W.; Machine: xTool xTool F1 Ultra (Fiber) (fiber, 2W)', 'scraped_public', true, 'engrave', 1.0);
