INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Walnut', 0, 90.0, 4000.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: xTool xTool M1 (diode, 10W); Air assist: on', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('HTV Vinyl', 0, NULL, 4800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BLADE CUT ONLY — do not use laser on vinyl/HTV (toxic fumes from PVC). In XCS select ''Blade Cut'' and select ''PU Heat Transfer Vinyl'' or ''Adhesive Vinyl'' from material library. Official xTool recommended settings: pressure 320g, speed 80mm/s, 1 pass for standard HTV. For printable HTV: pressure 85g, speed 80mm/s, 1 pass for outline cut. Place HTV shiny-side-down on cutting mat; mirror your design before cutting. Use fine-point blade. Source: xTool official HTV cutting guide (xtool.com/blogs/how-to/cut-iron-on-vinyl); Creative Ramblings vinyl cutting with M1 (creativeramblingsblog.com); Silhouette School M1 vinyl cut guide; Alanda Craft HTV with M1.; Machine: xTool xTool M1 (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Genuine Leather', 0, 60.0, 4200.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Leather needs moderate power and moderate-to-high speed to avoid burning. Community-confirmed range: power 20–60%, speed 60–80mm/s, 1 pass. ShawnMosch M1 guide documents power ~20% at 80mm/s for light surface mark on patches; Keeping It Simple Crafts used power 60% for a deeper engrave on thick genuine leather. Start at 40% power / 70mm/s and adjust — leather type (veg-tan vs chrome-tan) significantly affects results. Veg-tan takes deeper marks; chrome-tan burns faster. Do NOT use air assist for leather engraving (spreads char into the grain). Source: ShawnMosch xTool M1 laser engraving settings (shawnmosch.com/laser-engraving-settings/); Keeping It Simple Crafts leather logo guide (keepingitsimplecrafts.com); xTool leather laser engraving guide.; Machine: xTool xTool M1 (diode, 10W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Cardstock (80–110 lb / ~220–300 gsm)', 0, NULL, 4800.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Blade cut mode — laser is NOT used for cardstock cutting on the M1 (fire risk with paper). Use the fine-point blade (not the standard blade; fine-point is rated for materials up to 1.5mm). In XCS select ''Blade Cut'' and choose cardstock from the material library — the software auto-populates cut pressure ~300g and speed ~80mm/s. One community user confirmed pressure 300g / speed 80mm/s successfully cuts cardstock. For heavier cardstock (300 gsm+) increase pressure to 350–380g. Use the cutting mat; mirror your design if needed. Source: xTool support article ''Use the Cutting Blade to Process Materials with xTool M1'' (support.xtool.com/article/1817); xTool community support thread M1 220gr cardstock (support.xtool.com/community-support/detail/3842); Creative Ramblings M1 vinyl cutting guide.; Machine: xTool xTool M1 (diode, 10W)', 'scraped_public', true, 'cut', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm MDF', 0, 100.0, 240.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Community-established baseline for M1 10W on 3mm MDF: 100% power, 4mm/s, typically 2–3 passes depending on MDF density and glue content. Air assist strongly recommended — reduces char, clears smoke from kerf, and improves cut-through. The Gadgeteer M1 review noted 4mm/s as the typical cut speed vs 13mm/s on the 40W S1. Without air assist expect 3 passes minimum; with air assist 2 passes often sufficient. Always use honeycomb table to allow air through the cut. Source: xTool MDF laser cutting guide (xtool.com/blogs/xtool-academy/laser-cut-mdf); The Gadgeteer M1 review; xTool support community cut settings thread.; Machine: xTool xTool M1 (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 3.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('Slate (coaster)', 0, 30.0, 10800.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Settings confirmed by an M1 10W user in the xTool community support thread for photo engraving on slate coasters (support.xtool.com/community-support/detail/8197). Power 30%, Speed 180mm/s, 1 pass. Low power + high speed produces best contrast on slate — going darker tends to over-ablate and lose detail. For vector/line art you can push to 50% power at 150mm/s. Source: xTool community support (M1 10w engraving photo on slate / rock coaster); ShawnMosch M1 settings; xTool official slate coaster guide.; Machine: xTool xTool M1 (diode, 10W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('3mm Tinted Acrylic', 0, 100.0, 3600.0, NULL, NULL, NULL, NULL, NULL, 0.1, NULL, NULL, 'Diode lasers cannot engrave clear/transparent acrylic — the 450nm wavelength passes straight through. Use tinted or opaque acrylic only. At 100% power / 60mm/s / 1 pass, community users report clean surface engraving on colored xTool acrylic sheets. Reduce speed to 40mm/s for deeper bite. Air assist not recommended for engraving acrylic (can cause flare-up on thin material). Source: xTool official acrylic engraving guide (xtool.com/blogs/xtool-academy/acrylic-engraving); Pigskins & Pigtails M1 acrylic review; ShawnMosch M1 settings guide.; Machine: xTool xTool M1 (diode, 10W)', 'scraped_public', true, 'engrave', 1.0);
INSERT INTO cuts (material, thickness_mm, power_pct, speed_mm_min, gas_type, gas_pressure_bar, focus_position_mm, nozzle_diameter_mm, nozzle_distance_mm, line_interval_mm, frequency_hz, quality_rating, notes, source, is_shared, operation_type, num_passes) VALUES ('6mm Baltic Birch Plywood', 6.0, 100.0, 300.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Machine: xTool xTool M1 (diode, 10W); Air assist: on', 'scraped_public', true, 'cut', 1.0);
